COPY public."BaiHoc" ("MaBaiHoc", "MaKhoaHoc", "TenBaiHoc", "ThuTu", "NoiDungLyThuyet", "TrangThai", "KyNang", "ChuDe", "FileAudio") FROM stdin;
cee71a1d-d1ac-4b8d-894d-212897a5e242	b0ecdb2b-fdf8-4a33-9536-dd5c1a47ed37	Bài nghe: T1_1	1	{"transcript": "Thanks for calling Riverside Auto Repair.\\nHow can I help you?\\nHi. I got my car repaired last week and\\nused your shuttle service to get a ride back\\nto my office. Can you tell me why there's\\na service charge on my invoice for using\\nthe shuttle? I've never had to pay that\\nbefore.\\nYes, unfortunately the cost of auto fuel\\nhas risen quite a bit, so the company now\\nrequires us to charge for the shuttle.\\nWell, I wasn't expecting that.\\nI'm sorry we didn't inform you of this\\nahead of time. 341'11 waive the fee now, but\\nplease be aware that you'll have to pay for\\nrides in the future."}	ACTIVE	LISTENING	T1_1	audios/T1_1.mp3
00c6ac63-cbbe-42d1-838d-d27cb1ce433f	5e0d4fc1-caa1-478f-b32a-648b4205098d	Bài nghe: T1_10	1	{"transcript": "Excuse me. My mobile phone is out of\\npower. Are there any tables here at the\\ncafe that are near a wall socket, so I can\\ncharge my phone while I have some coffee?\\nWell, we only have a few outlets. And ...\\nit looks like all the tables near them are\\noccupied. I'm sorry about that.\\nHmm. In that case, can you suggest\\nanywhere nearby where I might be able to\\nsit for a few minutes and charge my phone,\\nthen?\\nYou know, the public library would be\\nperfect for that, and it's just a block up the\\nhill. You'll see it on the corner of Willow\\nStreet."}	ACTIVE	LISTENING	T1_10	audios/T1_10.mp3
96852a0b-f4dc-4671-a152-2693126072b0	5e0d4fc1-caa1-478f-b32a-648b4205098d	Bài nghe: T1_11	2	{"transcript": "Attention all listeners! Palmer's Gym\\nnow has several locations in your area. We\\nhave everything you need to keep fit, including\\nexercise classes and fitness instructors ready to\\nhelp you! But that's not all. Starting in April,\\nyour membership gives you access to any of our\\nlocations across the country. So if you're traveling\\nfor business or just on vacation, you won't have to\\nskip your workout routine! Visit our Web site to\\nsee a map of all the Palmer's Gym locations across\\nthe nation!"}	ACTIVE	LISTENING	T1_11	audios/T1_11.mp3
ca60ec5d-4bb2-4e32-8312-1886000091a6	5e0d4fc1-caa1-478f-b32a-648b4205098d	Bài nghe: T1_12	3	{"transcript": "Before we end this meeting, I want to\\nthank everyone for the extra hours you've put\\nin getting our new line of camera accessories\\nready for market. Because of your willingness\\nto work overtime, the new products will be\\nready in time for the trade show coming up next\\nmonth in Shanghai. That's in addition to the\\naccessories we usually display, but it shouldn't be\\na problem. We've reserved a booth at the front of\\nthe exhibition hall this year, and it's a large space."}	ACTIVE	LISTENING	T1_12	audios/T1_12.mp3
2d702a40-ce2a-4409-bc97-33fd5a0beef4	a5ef594e-eb57-43a7-b80b-68d5d500b15c	Bài nghe: T1_13	1	{"transcript": "Good evening. My name's Mateo and I'll be\\nserving you tonight. Since this is your first time\\nhere, let me tell you about our restaurant. AII the\\nvegetable products you see on the menu come\\nfrom our very own vegetable garden. The owner\\nof the cafe, Natasha, is a talented gardener who\\ngrows our fresh produce herself. Now, tonight\\nwe have a special entree. It's poached salmon,\\ncaught fresh today. It's a simple dish, served with\\na lemon sauce and a salad. I eat it all the time. So,\\nwhile you read over the menu, can I bring you a\\nbeverage?"}	ACTIVE	LISTENING	T1_13	audios/T1_13.mp3
6a0cc24e-71ec-40f3-abee-5f0ca002d4b1	a5ef594e-eb57-43a7-b80b-68d5d500b15c	Bài nghe: T1_14	2	{"transcript": "Welcome aboard this morning's direct\\nflight to Toronto. We look forward to flying with\\nyou today. Unfortunately, we've run out of space\\nin the overhead bins for larger carry-on bags. If\\nyour bag won't fit under your seat, we' ll take it\\nfrom you and check it. You'll be able to pick it up\\nat the baggage claim when we land. In addition,\\nwe have several meal options for purchase today.\\nOur standard selections are listed in the magazine\\nin the seat pocket in front of you. If you would\\nlike to purchase a meal, please notify a flight\\nattendant."}	ACTIVE	LISTENING	T1_14	audios/T1_14.mp3
c3458c25-5efe-45b0-b3c0-464af5e1803b	a5ef594e-eb57-43a7-b80b-68d5d500b15c	Bài nghe: T1_15	3	{"transcript": "Hello. It's Dana, one of your truck drivers.\\nI'm supposed to deliver kitchen appliances to\\nour store branches in Syracuse. I'm looking for\\none of the branches, and according to the list I\\nwas given, there should be a store at  Thistle\\nLane. Well, I've driven up and down the whole\\nroad, and all I see are houses. I'll deliver the\\nappliances to the other stores on my list, but while\\nI'm doing that, could you please get back to me\\nwith the correct address?"}	ACTIVE	LISTENING	T1_15	audios/T1_15.mp3
