p on - tiếp tục"}, {"content": "", "heading": "Keep under - đè nén, thống trị"}, {"content": "", "heading": "Keep up - giữ vững, giữ không cho đổ"}, {"content": "", "heading": "22."}, {"content": "", "heading": "Look about - đợi chờ"}, {"content": "", "heading": "Look after - chăm sóc"}, {"content": "", "heading": "Look at - ngắm nhìn"}, {"content": "", "heading": "Look away - quay đi"}, {"content": "", "heading": "Look back - quay lại, ngoái cổ lại"}, {"content": "", "heading": "Look back upon - nhìn lại cái gì đã qua"}, {"content": "", "heading": "Look down - nhìn xuống"}, {"content": "", "heading": "Look down on - coi thường"}, {"content": "", "heading": "Look up to - kính trọng"}, {"content": "", "heading": "Look for - tìm kiếm"}, {"content": "", "heading": "Look forward to - mong đợi"}, {"content": "", "heading": "Look in - nhìn vào, ghé qua thăm"}, {"content": "", "heading": "Look into - xem xét kỹ, nghiên cứu"}, {"content": "", "heading": "Look on - đứng xem"}, {"content": "", "heading": "Look out - để ý, coi chừng"}, {"content": "", "heading": "Look out for st - trông chừng cái gì"}, {"content": "", "heading": "Look over - xem xét, kiểm tra, tha thứ, bỏ qua"}, {"content": "", "heading": "Look round - nhìn quanh"}, {"content": "", "heading": "Look through - lờ đi, xem lướt qua"}, {"content": "", "heading": "Look up - nhìn lên, tra cứu"}, {"content": "", "heading": "23."}, {"content": "", "heading": "Lay aside - gác sang một bên, không nghĩ tới"}, {"content": "", "heading": "Lay down - để xuống, xác lập, đề ra"}, {"content": "", "heading": "Lay for - nằm đợi"}, {"content": "", "heading": "Lay in - dự trữ, để dành"}, {"content": "", "heading": "Lay sb off - cho ai nghỉ việc"}, {"content": "", "heading": "Lay on - đánh, giáng đòn"}, {"content": "", "heading": "Lay out - sắp đặt, bố trí, đưa ra"}, {"content": "", "heading": "Lay over - trải lên, phủ lên"}, {"content": "", "heading": "24."}, {"content": "", "heading": "Let by - để cho đi qua"}, {"content": "", "heading": "Let down - làm cho ai đó thất vọng"}, {"content": "", "heading": "Let in - cho vào"}, {"content": "", "heading": "Let off - tha thứ"}, {"content": "", "heading": "Let on - để lộ, tiết lộ"}, {"content": "", "heading": "Let out - để cho đi ra, để cho chạy thoát"}, {"content": "", "heading": "Let up - dịu, ngót"}, {"content": "", "heading": "25."}, {"content": "", "heading": "Make after - theo đuổi"}, {"content": "", "heading": "Make against - bất lợi, có hại cho"}, {"content": "", "heading": "Make at - tiến tới, tấn công ai"}, {"content": "", "heading": "Make away - vội vàng ra đi"}, {"content": "", "heading": "Make away with - huỷ hoại, thủ tiêu, giết"}, {"content": "", "heading": "Make off - chuồn, cuốn gói"}, {"content": "", "heading": "Make off with - ăn cắp"}, {"content": "", "heading": "Make out - hiểu"}, {"content": "", "heading": "Make over - chuyển, nhượng"}, {"content": "", "heading": "Make up - trang điểm, bịa đặt, quyết định, làm hoà"}, {"content": "", "heading": "Make for - tiến về hướng"}, {"content": "", "heading": "Make up of - bao gồm"}, {"content": "", "heading": "Make use of - lợi dụng"}, {"content": "", "heading": "Make up for - bù lại"}, {"content": "", "heading": "26."}, {"content": "", "heading": "Pass away - qua đời"}, {"content": "", "heading": "Pass sb/st by - lờ đi, làm ngơ"}, {"content": "", "heading": "Pass for - được coi là, có tiếng là"}, {"content": "", "heading": "Pass off - mất đi, biến mất (cảm giác)"}, {"content": "", "heading": "Pass on - truyền lại"}, {"content": "", "heading": "Pass out - mê man, bất tỉnh"}, {"content": "", "heading": "Pass over - băng qua"}, {"content": "", "heading": "Pass round - chuyền tay, chuyền theo vòng"}, {"content": "", "heading": "Pass through - trải qua, kinh qua"}, {"content": "", "heading": "Pass up - từ bỏ, khước từ"}, {"content": "", "heading": "27."}, {"content": "", "heading": "Pick at - chế nhạo, chế giễu, rầy la"}, {"content": "", "heading": "Pick off - nhổ đi"}, {"content": "", "heading": "Pick up - nhặt, đón"}, {"content": "", "heading": "28."}, {"content": "", "heading": "Put aside - để dành, gạt sang một bên"}, {"content": "", "heading": "Put back - để lại (chỗ cũ)"}, {"content": "", "heading": "Put by - lảng tránh"}, {"content": "", "heading": "Put down - đặt xuống"}, {"content": "", "heading": "Put in - đệ đơn"}, {"content": "", "heading": "Put in for - đòi, yêu sách"}, {"content": "", "heading": "Put off - hoãn"}, {"content": "", "heading": "Put on - mặc (quần áo), đội (mũ), đi (giày)...."}, {"content": "", "heading": "Put out - dập tắt"}, {"content": "", "heading": "Put through - hoàn thành, xong xuôi"}, {"content": "", "heading": "Put up - dựng lên"}, {"content": "", "heading": "Put sb up - cho ai đó ở nhờ"}, {"content": "", "heading": "Put up with - chịu đựng"}, {"content": "", "heading": "29."}, {"content": "", "heading": "Take after = look like - giống"}, {"content": "", "heading": "Take along - mang theo, đem theo"}, {"content": "", "heading": "Take away - mang đi, lấy đi"}, {"content": "", "heading": "Take back - lấy lại, mang về"}, {"content": "", "heading": "Take down - tháo xuống, hạ xuống"}, {"content": "", "heading": "Take in - hiểu, lừa gạt"}, {"content": "", "heading": "Take off - cởi, cất cánh"}, {"content": "", "heading": "Take on - đảm nhiệm, thuê mướn"}, {"content": "", "heading": "Take out - nhổ (cây, răng), đổ (rác)"}, {"content": "", "heading": "Take over - tiếp quản, kế tục"}, {"content": "", "heading": "Take to - thích"}, {"content": "", "heading": "Take up - tiếp tục một công việc bỏ dở"}, {"content": "", "heading": "30."}, {"content": "", "heading": "Turn away - ngoảnh mặt đi"}, {"content": "", "heading": "Turn back - quay lại"}, {"content": "", "heading": "Turn down - vặn nhỏ, từ chối"}, {"content": "", "heading": "Turn into - biến thành"}, {"content": "", "heading": "Turn off - tắt đi"}, {"content": "", "heading": "Turn on - bật lên"}, {"content": "", "heading": "Turn out - hoá ra"}, {"content": "", "heading": "Turn over - lật, dở"}, {"content": "", "heading": "Turn up = show up = arrive - đến, xuất hiện"}, {"content": "", "heading": "31."}, {"content": "", "heading": "Try on - thử đồ"}, {"content": "", "heading": "Try out = test - kiểm tra xem có hoạt động được hay không"}, {"content": "", "heading": "32."}, {"content": "", "heading": "Tell against - nói điều chống lại"}, {"content": "", "heading": "Tell off - rầy, la mắng"}, {"content": "", "heading": "Tell on - mách"}, {"content": "", "heading": "Tell over - đếm"}, {"content": "", "heading": "Tell sb/st apart - phân biệt ai/cái gì"}, {"content": "", "heading": "33."}, {"content": "", "heading": "See about - đảm đương"}, {"content": "", "heading": "See after - săn sóc, để ý tới"}, {"content": "", "heading": "See off - tiễn"}, {"content": "", "heading": "34."}, {"content": "", "heading": "Set against - so sánh, đối chiếu"}, {"content": "", "heading": "Set apart - dành riêng ra"}, {"content": "", "heading": "Set back - vặn chậm lại"}, {"content": "", "heading": "Set down - ghi lại, chép lại"}, {"content": "", "heading": "Set off/out - khởi hành"}, {"content": "", "heading": "Set up - thành lập"}, {"content": "", "heading": "35."}, {"content": "", "heading": "Stay away - không đến, vắng mặt"}, {"content": "", "heading": "Stay in - không ra ngoài"}, {"content": "", "heading": "Stay out - ở ngoài, không về nhà"}, {"content": "", "heading": "Stay on - ở lâu hơn dự định"}, {"content": "", "heading": "Stay up - thức"}, {"content": "", "heading": "36."}, {"content": "", "heading": "Stand by - đứng cạnh"}, {"content": "", "heading": "Stand for - viết tắt, tượng trưng cho"}, {"content": "", "heading": "Stand in - đại diện cho"}, {"content": "", "heading": "Stand in with - vào hùa, cấu kết với"}, {"content": "", "heading": "Stand off - tránh xa, lảng xa"}, {"content": "", "heading": "Stand on - giữ đúng, khăng khăng đòi"}, {"content": "", "heading": "Stand out - nổi bật"}, {"content": "", "heading": "Stand over - bị hoãn lại"}, {"content": "", "heading": "Stand up - đứng dậy"}, {"content": "", "heading": "Stand up for - về phe, ủng hộ"}, {"content": "", "heading": "Stand up to - dũng cảm đương đầu"}, {"content": "", "heading": "Stand in for - thay thế chỗ của ai"}, {"content": "", "heading": "37."}, {"content": "", "heading": "Run after - theo đuổi ai"}, {"content": "", "heading": "Run against - đi ngược lại, chống đối, phản đối"}, {"content": "", "heading": "Run along - rời đi, tránh ra xa"}, {"content": "", "heading": "Run down - hao mòn, tiều tuỵ"}, {"content": "", "heading": "Run out - cạn kiệt"}, {"content": "", "heading": "Run out of - hết sạch cái gì"}, {"content": "", "heading": "Run on - chạy bằng cái gì"}, {"content": "", "heading": "Run over - cán lên, đè lên"}, {"content": "", "heading": "Run through - tiêu xài phung phí"}, {"content": "", "heading": "38."}, {"content": "", "heading": "Watch after - dõi theo, nhìn theo"}, {"content": "", "heading": "Watch for - chờ, đợi"}, {"content": "", "heading": "Watch out - đề phòng, coi chừng"}, {"content": "", "heading": "Watch over - trông nom, canh gác"}, {"content": "", "heading": "39."}, {"content": "", "heading": "Wear away - làm mòn dần, làm mất dần"}, {"content": "", "heading": "Wear down - làm kiệt sức dần"}, {"content": "", "heading": "Wear off - làm mòn mất"}, {"content": "", "heading": "Wear out - làm rách, làm sờn, làm mệt lử"}, {"content": "", "heading": "40."}, {"content": "", "heading": "Wipe at - quật, giáng cho một đòn"}, {"content": "", "heading": "Wipe away - tẩy, lau sạch"}, {"content": "", "heading": "Wipe out - xoá sạch"}]}	ACTIVE	GRAMMAR	CỤM ĐỘNG TỪ - PHRASAL VERBS	\N
68b703a9-14dd-4d02-9de7-6ffa9c1c3a17	135214f4-611e-45a7-a4b8-076794ab24a0	DANH ĐỘNG TỪ VÀ ĐỘNG TỪ NGUYÊN MẪU - GERUND & INFINITIVE VERB	3	{"title": "LÝ THUYẾT DĐT VÀ ĐTNM", "sections": [{"content": "", "heading": "DANH ĐỘNG TỪ VÀ ĐỘNG TỪ NGUYÊN MẪU – GERUND AND INFINITIVE VERB"}, {"content": "Danh động từ là những từ có cấu trúc như một động từ, nhưng lại có chức năng làm danh từ. Danh động từ là những động từ thêm \\"ing\\" để biến thành danh từ. Danh động từ có thể làm:", "heading": "I. Danh động từ (Gerund)"}, {"content": "(Nếu danh động từ làm chủ ngữ của câu thì động từ luôn chia theo ngôi thứ ba số ít.) Ví dụ: Walking in the rain gives me a pleasure. (Đi bộ dưới mưa cho tôi cảm giác dễ chịu.)", "heading": "1. Làm chủ ngữ"}, {"content": "", "heading": "2. Làm tân ngữ"}, {"content": "admit (thú nhận), appreciate (cảm kích), avoid (tránh), delay (hoãn lại), deny (phủ nhận), hate/ detest (ghét), enjoy (thích), imagine (tưởng tượng), involve (có liên quan), keep (giữ), mention (đề cập), mind (phiền), miss (bỏ lỡ), postpone (hoãn lại), practice (thực hành), recall (nhớ lại), resent (không hài lòng), resist (phản đối), risk (liều lĩnh), suggest (đề nghị), finish (hoàn thành), consider (xem xét, cân nhắc).... V\\ní dụ: Would you mind turning the radio down? (Phiền bạn vặn nhỏ đài được không?)", "heading": "a. Danh động từ làm tân ngữ trực tiếp sau các động từ như"}, {"content": "Adjective + preposition + gerund\\nNoun + preposition + gerund\\nVerb + preposition + gerund Ví dụ: Mary is crazy about playing tennis. (Mary rất thích chơi tennis.) There's no interest in writing letters. (Viết thư chẳng có gì thú vị cả.) Sue dreams of being a pop star. (Sue mơ trở thành ngôi sao nhạc Pop.)", "heading": "b. Danh động từ làm tân ngữ của giới từ"}, {"content": "be busy, can't/ couldn't help, can't stand/ bear / face, feel like, it's no good/ use, there's no point in, it's (not) worth....\\nCụ thể:\\nbe busy doing st: bận làm gì\\ncan't / couldn't help doing st: không thể nhịn được\\ncan't stand / bear / face doing st: không thể chịu được\\nit's no good / use doing st = there's no point in doing st: không đáng làm gì\\nit's (not) worth doing st: (không) đáng làm gì\\nVí dụ: She is busy cooking the meal. (Cô ấy đang bận nấu ăn.) She couldn't help laughing. (Cô ấy không nhịn được cười.)", "heading": "c. Danh động từ được dùng sau các cụm từ:"}, {"content": "", "heading": "3. Làm bổ ngữ"}, {"content": "Ví dụ: My habit is sleeping whenever I'm sad. (Thói quen của tôi là ngủ bất cứ khi nào có chuyện buồn.)", "heading": "Danh động từ làm bổ ngữ của chủ ngữ"}, {"content": "Ví dụ: My hobby, playing table tennis, makes me feel happy. (Sở thích của tôi, chơi bóng bàn, làm cho tôi thấy vui vẻ.)", "heading": "4. Làm ngữ đồng vị"}, {"content": "", "heading": "5. Làm danh từ ghép"}, {"content": "", "heading": "Cấu tạo danh từ ghép: a. gerund + noun Ví dụ: cooking-oil (dầu ăn), sleeping-pill (thuốc ngủ) b. noun + gerund Ví dụ: child-rearing (nuôi dạy con), child-bearing (việc sinh con)"}, {"content": "", "heading": "Lưu ý:"}, {"content": "Danh động từ có hình thức dễ nhận thấy là có dạng V-ing. Tuy nhiên, không phải tất cả các từ có đuôi -ing đều là danh động từ. Hiện tại phân từ (Present Participle) cũng có đuôi -ing sau động từ.\\nTuy nhiên, Present Participle và Gerund là hai khái niệm hoàn toàn khác nhau. Vậy làm sao để có thể biết chắc chắn đây là “Hiện tại phân từ” hay Gerund?\\nTrong câu, chức năng của một “Hiện tại phân từ” là tính từ (adjective), còn chức năng của “Gerund” là danh từ (noun). Mặc dù cả hai đều có hình thức (form) giống nhau nhưng chức năng trong câu là hoàn toàn khác.\\nChức năng của phân từ hiện tại:", "heading": "1. Sự khác nhau giữa danh động từ (gerund) và phân từ hiện tại (present participle)"}, {"content": "Ví dụ:\\nIt is raining now. (Present progressive)\\n(Trời đang mưa)\\nWe will be studying English at this time tomorrow. (Future progressive)\\n(Chúng tôi sẽ đang học tiếng Anh vào giờ này ngày mai)", "heading": "a. Dùng trong các thì tiếp diễn: be + Present participle (V-ing)"}, {"content": "Ví dụ:\\nThe film is interesting.\\n(Bộ phim thật hấp dẫn)\\nIt’s an exciting journey.\\n(Đó là một chuyến đi thú vị)", "heading": "b. Dùng như một tính từ (mang nghĩa chủ động và thường miêu tả vật)"}, {"content": "", "heading": "c. Thay cho một mệnh đề"}, {"content": "Ví dụ:\\nHe washed his car and sang happily.\\n(Anh ấy đã rửa xe và hát rất vui vẻ)\\n→ Washing his car, he sang happily.\\n→ He washed his car, singing happily.", "heading": "Mệnh đề độc lập trong câu ghép: Hai sự kiện xảy ra đồng thời cùng một chủ từ thì một trong hai mệnh đề có thể được thay bằng hiện tại phân từ."}, {"content": "Ví dụ:\\nShe put on her coat and went out.\\n(Cô ấy mặc áo khoác và ra ngoài)\\n→ Putting on her coat, she went out.", "heading": "Hai sự kiện xảy ra kế tiếp nhau: sự kiện xảy ra trước được thay bằng hiện tại phân từ."}, {"content": "Ví dụ:\\nThe girl who lent me this book is my best friend.\\n(Cô gái cho tôi mượn cuốn sách này là bạn thân của tôi.)\\n→ The girl lending me this book is my best friend.\\nMệnh đề trạng ngữ chỉ thời gian:\\nVí dụ:\\nSince he left school, he has worked in a restaurant.\\n(Từ khi rời khỏi trường, anh ấy vẫn làm việc ở một nhà hàng)\\n→ Leaving school, he has worked in a restaurant.\\nMệnh đề trạng ngữ chỉ lí do: hai mệnh đề phải cùng chủ từ\\nVí dụ:\\nBecause he drove carelessly, he had an accident.\\n(Vì lái xe không cẩn thận, anh ấy đã gây tai nạn)\\n→ Driving carelessly, he had an accident.", "heading": "Mệnh đề phụ trong câu (Mệnh đề quan hệ): khi đại từ quan hệ làm chủ từ và mệnh đề quan hệ là mệnh đề chủ động thì được thay bằng hiện tại phân từ."}, {"content": "", "heading": "d. Cấu trúc câu: S + sit/ stand / lie / come / run (cụm từ chỉ nơi chốn) + present participle\\nVí dụ:\\nHe sat on the chair reading books.\\n(Anh ấy đang ngồi trên ghế và đọc sách)"}, {"content": "f. Sau một số động từ tri giác (see, hear, smell, feel, taste, overhear...), catch, find, spend, waste\\nVí dụ:\\nI saw your children playing on the street.\\n(Tôi thấy lũ trẻ chơi trên phố)\\nShe caught her little son reading her letters.\\n(Cô ấy bắt gặp cậu con nhỏ đang đọc thư của mình)", "heading": "e. Cấu trúc: There + be + Noun + present participle\\nVí dụ:\\nThere are many people waiting for the bus.\\n(Có nhiều người đang đợi xe bus)"}, {"content": "", "heading": "Danh động từ hoàn thành (Perfect Gerund) và Phân từ hoàn thành (Perfect Participle)\\nHình thức: Having + Vp2"}, {"content": "Dùng thay cho hình thức hiện tại của danh động từ khi chúng ta đề cập đến hành động trong quá khứ.\\nVí dụ:\\nHe was accused of having stolen their money. (Anh ta bị buộc tội đã lấy cắp tiền của họ)", "heading": "a. Perfect Gerund (Danh động từ hoàn thành)"}, {"content": "Dùng rút ngắn mệnh đề khi hành động trong mệnh đề đó xảy ra trước.\\nVí dụ:\\nHe finished all his homework and then he went to bed.\\n(Anh ấy làm xong bài tập và rồi đi ngủ)\\n→ Having finished all his homework, he went to bed.", "heading": "b. Perfect participle (Phân từ hoàn thành)"}, {"content": "Ví dụ:\\nAfter he had fallen from the horse back, he was taken to hospital and had an operation. (sau khi bị ngã ngựa. anh ấy được đưa vào viện để làm phẫu thuật)\\n→ After having fallen from the horse back, he was taken to hospital and had an operation.", "heading": "Dùng rút ngắn mệnh đề trạng ngữ chỉ thời gian"}, {"content": "Động từ nguyên mẫu có “to” được dùng làm:", "heading": "II. Động từ nguyên mẫu có TO (TO INFINITIVE VERB)"}, {"content": "", "heading": "1. Chủ ngữ Ví dụ: To master a foreign language is necessary. (Thông thạo một ngoại ngữ là cần thiết.)"}, {"content": "afford (có đủ khả năng), agree (đồng ý), arrange (sắp xếp), appear (hoá ra là), ask (yêu cầu), attempt (nỗ lực), care (quan tâm), choose (chọn), claim (thú nhận), decide (quyết định), demand (yêu cầu), deserve (xứng đáng), expect (mong muốn), fail (thất bại), happen (tình cờ), hesitate (ngập ngừng), hope (hy vọng), intend (dự định), learn (học), manage (xoay xở), neglect (sao nhãng), offer (cho), plan (có kế hoạch), prepare (chuẩn bị), pretend (giả vờ), promise (hứa), propose (đề nghị), refuse (từ chối), seem (hình như), swear (thề), tend (có khuynh hướng), threaten (doạ), vow (thề), wait (chờ), want (muốn), wish (ước mơ), would like (muốn, thích), yearn (khát khao), urge (thúc giục)…..\\nVí dụ:\\n- We decided to have a baby. (Chúng tôi quyết định có con.)\\n- They plan to go abroad next year. (Năm sau họ định đi nước ngoài.)", "heading": "2. Tân ngữ a. To-infinitive làm tân ngữ trực tiếp sau các động từ"}, {"content": "Ví dụ: I've made up my mind to be a teacher. (Tôi đã quyết định sẽ làm giáo viên.)\\nc. To-infinitive thường được dùng sau các tính từ diễn tả cảm xúc, phản ứng và một số các tính từ thông dụng khác (un) able (có/không thể), delighted (vui sướng), proud (tự hào), glad (vui mừng), ashamed (xấu hổ), afraid (e ngại), eager (háo hức), surprised (ngạc nhiên), anxious (lo lắng), pleased (hân hạnh), annoyed (bực mình), happy (hạnh phúc), ready (sẵn sàng), curious (tò mò)......\\nVí dụ: I'm curious to know what he said. (Tôi muốn biết anh ấy đã nói gì.) It's nice to meet you here. (Thật vui khi gặp bạn ở đây.)", "heading": "b. To-infinitive cũng được dùng sau các cụm từ to make up one's mind, to take care, to make sure, to take the trouble, ..."}, {"content": "Ví dụ:\\n- I do not know what to do. (Tôi không biết phải làm gì?)\\n- Can you tell me how to get to the bus stop? (Làm ơn chỉ cho tôi làm thế nào để đến trạm xe buýt.)", "heading": "d. To-infinitive dùng sau các nghi vấn từ trong lời nói gián tiếp (ngoại trừ why)"}, {"content": "", "heading": "3. Bổ ngữ của chủ ngữ hoặc tân ngữ (subjective/ objective complements) a"}, {"content": "Ví dụ: What you have to do is to work harder. (Những gì bạn phải làm là học hành chăm chỉ hơn.)", "heading": ". To-infinitive làm bổ ngữ của chủ ngữ"}, {"content": "advise, allow/ permit, ask, assume, beg, believe, cause, challenge, command, compel, consider, enable, encourage, expect, find, forbid, force, get, guess, hate, help, imagine, intend, instruct, invite, know, lead, like, leave, love, mean, need, observe, order, permit, prefer, persuade, remind, request, suspect, teach, tell, tempt, think, trust, urge, understand, want, warn, wish,...\\nVí dụ: My mother wants me to become a doctor. (Mẹ tôi muốn tôi trở thành bác sĩ.)", "heading": "b. To-infinitive làm bổ ngữ của tân ngữ, sau động từ + tân ngữ"}, {"content": "", "heading": "4. Trong các cấu trúc:"}, {"content": "Ví dụ: It takes me 30 minutes to go to school every day. (Mỗi ngày tôi mất 30 phút để tới trường.)", "heading": "a. It takes / took + O + thời gian + to-inf: mất của ai đó bao nhiêu thời gian để làm gì"}, {"content": "Ví dụ: I'm trying my best to study English well in order to find a better job. (Tôi đang cố gắng hết sức để học tốt tiếng Anh để mà tìm được một công việc tốt hơn.)", "heading": "b. Chỉ mục đích: so as to/ in order to/ to-inf"}, {"content": "Ví dụ: I have some letters to write. (Tôi có vài lá thư phải viết.) Is there anything to eat? (Có gì để ăn không?)", "heading": "c. Bổ ngữ cho danh từ hoặc đại từ: S + V + Noun/ pronoun + to-inf"}, {"content": "Ví dụ: It is interesting to study English. (Thật thú vị để học tiếng Anh)", "heading": "d. It + be + adj + to-inf: thật... để ..."}, {"content": "Ví dụ: The exercise is too difficult for me to do. (Bài tập đó quá khó cho tôi để giải.)", "heading": "e. S + V + too + adj / adv+ (for sb)+ to-inf (quá cho ai đó để làm gì)"}, {"content": "Ví dụ: She isn't old enough to go to school. (Con bé chưa đủ tuổi để đến trường.)", "heading": "f. S + V + adj / adv + enough + (for sb) + to-inf (đủ cho ai đó để làm gì)"}, {"content": "Ví dụ: I find it difficult to learn English vocabulảy (Tôi thấy rất khó để học từ vựng).\\nDưới đây là văn bản được trích xuất từ 3 hình ảnh bạn đã cung cấp, giữ nguyên nội dung và cấu trúc trình bày:", "heading": "g. S + find + it + adj + to-inf:"}, {"content": "Động từ nguyên mẫu không to được dùng:", "heading": "III. Động từ nguyên mẫu không to (BARE INFINITIVE VERB)"}, {"content": "Sau các động từ: let, make, help, see, hear, feel, watch, notice + tân ngữ. Ví dụ: We saw her get off the bus. (Chúng tôi thấy cô ta bước xuống xe buýt.) The boss made us work so hard. (Ông chủ bắt chúng tôi làm việc nhiều quá.) Lưu ý: Trong câu bị động thì ta lại phải dùng động từ nguyên mẫu có “to” sau những động từ trên. Ví dụ: She was seen to get off the bus. We were made to work so hard (by the boss).", "heading": "Sau các trợ động từ tình thái (modal verbs). Ví dụ: We must go now. (Giờ chúng tôi phải đi.)"}, {"content": "", "heading": "Sau các cụm động từ had better, would rather, had sooner và sau why hoặc why not. Ví dụ: I would rather stay at home. (Tôi thích ở nhà hơn.) Why not stay for lunch? (Sao không ở lại ăn trưa?)"}, {"content": "Có một số động từ trong tiếng Anh có thể theo sau cả một danh động từ hoặc động từ nguyên mẫu. Tuy nhiên, nghĩa của mỗi cấu trúc có thay đổi.", "heading": "IV. Danh động từ, động từ nguyên mẫu có to hay động từ nguyên mẫu không to (GERUND, TO INFINITIVE, OR BARE INFINITIVE)"}, {"content": "", "heading": "Với những động từ tri giác see, hear, feel, ... + O + bare-inf. (chỉ sự hoàn tất của hành động) + V-ing (chỉ sự tiếp diễn của hành động)"}, {"content": "", "heading": "Ví dụ: Mary heard the boy cough. (Mary nghe thấy thằng bé ho.)"}, {"content": "", "heading": "They saw the thief breaking into the house. (Họ thấy tên trộm đang đột nhập vào nhà.)"}, {"content": "", "heading": "advise, recommend, allow, permit, encourage, require + V-ing + object + to-infinitive"}, {"content": "", "heading": "Ví dụ: They do not permit us to smoke here. (Họ không cho chúng tôi hút thuốc ở đây.)"}, {"content": "", "heading": "They do not permit smoking here. (Họ không cho hút thuốc ở đây.)"}, {"content": "", "heading": "forget / remember + to infinitive (chỉ hành động ở tương lai) + V-ing (chỉ hành động đã qua)"}, {"content": "", "heading": "Ví dụ: Remember to call Peter. (Nhớ gọi điện cho Peter đấy.)"}, {"content": "", "heading": "I remember calling him yesterday. (Tôi nhớ là đã gọi cho anh ấy hôm qua.)"}, {"content": "", "heading": "stop + to infinitive (ngừng việc này để làm việc khác) + V-ing (thôi không làm nữa)"}, {"content": "", "heading": "Ví dụ: He stopped to go home early. (Anh ấy nghỉ để về nhà sớm.)"}, {"content": "", "heading": "He stopped working because he was tired. (Anh ấy nghỉ làm vì anh ấy mệt.)"}, {"content": "", "heading": "try + to infinitive (cố gắng - chỉ sự nỗ lực) + V-ing (thử - chỉ sự thử nghiệm)"}, {"content": "", "heading": "Ví dụ: He always tries to learn better. (Anh ấy luôn cố học giỏi hơn.)"}, {"content": "", "heading": "Sam tried opening the lock with a paperclip. (Sam thử mở cửa bằng cái kẹp giấy.)"}, {"content": "", "heading": "regret + to infinitive (rất lấy làm tiếc khi làm gì - chưa làm) + V-ing (hồi tiếc vì đã làm gì)"}, {"content": "", "heading": "Ví dụ: I regret to inform you that your application letter has been turned down. (Tôi rất lấy làm tiếc để thông báo với bạn rằng đơn xin việc của bạn đã bị từ chối.)"}, {"content": "", "heading": "I regret telling him the truth. (Tôi hối tiếc vì đã nói với anh ấy sự thật.)"}, {"content": "", "heading": "mean + to infinitive (chỉ dự định hoặc ý định) + V-ing (chỉ sự liên quan hoặc kết quả)"}, {"content": "", "heading": "Ví dụ: I meant to go earlier. (Tôi đã định đi sớm hơn.)"}, {"content": "", "heading": "This new order will mean working overtime. (Mệnh lệnh mới này có nghĩa là phải làm thêm giờ.)"}, {"content": "", "heading": "need + to infinitive (nghĩa chủ động) + V-ing (nghĩa bị động)"}, {"content": "", "heading": "Ví dụ: You need to do everything with care. (Bạn cần làm mọi việc thật cẩn thận.)"}, {"content": "", "heading": "Everything needs doing (= to be done) with care. (Mọi việc cần được làm thật cẩn thận.)"}, {"content": "", "heading": "go on + to infinitive (chỉ sự thay đổi của hành động) + V-ing (chỉ sự liên tục của hành động)"}, {"content": "", "heading": "Ví dụ: She stopped talking about that and went on to describe her other problems. (Cô ta thôi không nói về điều đó nữa mà chuyển sang mô tả một vấn đề khác.)"}, {"content": "", "heading": "She went on talking about her illness until we all went to sleep. (Cô ấy cứ nói mãi về căn bệnh của mình cho đến khi chúng tôi đi ngủ.)"}, {"content": "", "heading": "Begin, start, like, love, hate, continue... có thể được theo sau bởi động từ nguyên mẫu hoặc danh động từ, không có sự khác biệt về nghĩa."}, {"content": "", "heading": "Ví dụ: I began to learn/learning English three years ago. (Tôi bắt đầu học tiếng Anh cách đây 3 năm)"}, {"content": "", "heading": "They like dancing / to dance. (Họ thích khiêu vũ.)"}, {"content": "", "heading": "Sau help + object có thể là một động từ nguyên mẫu có to hoặc không to."}, {"content": "", "heading": "Ví dụ: He helped us (to) repair the car. (Anh ấy giúp chúng tôi sửa xe ô tô.)"}]}	ACTIVE	GRAMMAR	DANH ĐỘNG TỪ VÀ ĐỘNG TỪ NGUYÊN MẪU - GERUND & INFINITIVE VERB	\N
19d21384-76db-4c98-937f-a773a7f2c0cd	a8efe662-9202-4e83-822d-808656858e3e	GIỚI TỪ - PREPOSITIONS	3	{"title": "LÝ THUYẾT GIỚI TỪ", "sections": [{"content": "", "heading": "GIỚI TỪ - PREPOSITIONS"}, {"content": "", "heading": "A. LÍ THUYẾT"}, {"content": "Giới từ là từ hay cụm từ thường được dùng với danh từ, tính từ, đại từ để chỉ mối liên hệ giữa các từ này với các thành phần khác trong câu.", "heading": "I. Định nghĩa giới từ"}, {"content": "Giới từ có vị trí đứng riêng của mình trong câu, sau đây là vị trí của một số giới từ cơ bản trong tiếng Anh:", "heading": "II. Vị trí của giới từ"}, {"content": "", "heading": "1. Trước danh từ Ví dụ:"}, {"content": "", "heading": "at the cinema: ở rạp chiếu phim"}, {"content": "", "heading": "in 2000: vào năm 2000"}, {"content": "", "heading": "2. Sau động từ Có thể liền sau động từ, có thể bị một từ khác xen giữa động từ và giới từ. Ví dụ:"}, {"content": "", "heading": "I arrived at the airport on time. (Tôi đến sân bay đúng giờ.)"}, {"content": "", "heading": "Please turn the radio down! (Làm ơn vặn nhỏ đài chút!)"}, {"content": "", "heading": "3. Sau tính từ Ví dụ:"}, {"content": "", "heading": "Viet Nam is rich in natural resources. (Việt Nam giàu tài nguyên thiên nhiên.)"}, {"content": "Dưới đây là nội dung chi tiết về các loại giới từ được trích xuất từ các hình ảnh bạn cung cấp:", "heading": "He is very friendly with me. (Anh ấy rất thân thiện với tôi.)"}, {"content": "", "heading": "III. Các loại giới từ"}, {"content": "", "heading": "1. Giới từ chỉ thời gian"}, {"content": "", "heading": "1. ON:"}, {"content": "Thứ trong tuần\\nNgày trong tháng/năm\\nTrong một số cụm từ:\\non holiday: đi nghỉ\\non vacation: nghỉ việc\\non business: đi công tác\\non duty: đang làm nhiệm vụ\\non an excursion: trong một chuyến du ngoạn\\non purpose: có chủ định\\non time: đúng giờ", "heading": "Cách dùng:"}, {"content": "", "heading": "Ví dụ:"}, {"content": "", "heading": "We have English lessons on Monday and Friday."}, {"content": "", "heading": "I was born on May 5th 1987."}, {"content": "", "heading": "She went on holiday with her family."}, {"content": "", "heading": "He doesn’t have anything to do because he has been on vacation."}, {"content": "", "heading": "The manager and the secretary are on business."}, {"content": "", "heading": "I’m sorry but I am on duty, so I can’t join you."}, {"content": "", "heading": "Last week, my class was on an excursion to Halong Bay."}, {"content": "", "heading": "I think they did it on purpose."}, {"content": "", "heading": "He is always on time. You can rely on him."}, {"content": "", "heading": "2. IN:"}, {"content": "Tháng/năm/mùa\\nBuổi trong ngày\\nTrong một số cụm từ:\\nin the future: trong tương lai\\nin the past: trong quá khứ\\nin (good) time for: kịp giờ\\nin good/bad mood: tâm trạng tốt/tệ\\nin the end: cuối cùng\\nin the beginning: lúc đầu", "heading": "Cách dùng:"}, {"content": "", "heading": "Ví dụ:"}, {"content": "", "heading": "In March/In 2017/In summer"}, {"content": "", "heading": "In the morning/afternoon/evening"}, {"content": "", "heading": "I wish to be a doctor in the future."}, {"content": "", "heading": "My village was very poor in the past."}, {"content": "", "heading": "Luckily, we are in good time for the meeting."}, {"content": "", "heading": "Today, I’m in bad mood. I don’t want to do anything."}, {"content": "", "heading": "In the end, we get married though we hated each other in the beginning."}, {"content": "", "heading": "3. AT:"}, {"content": "Trước các ngày lễ\\nCho cuối tuần\\nTrước giờ\\nCho một mốc thời gian nhất định:\\nat night: vào ban đêm\\nat noon: vào buổi trưa\\nat lunch time: vào giờ ăn trưa\\nat midday: vào giữa ngày\\nat the moment/ at present: bây giờ\\nat times: thỉnh thoảng\\nat dawn: khi bình minh\\nat dusk: khi hoàng hôn\\nat the same time: cùng lúc", "heading": "Cách dùng:"}, {"content": "", "heading": "Ví dụ:"}, {"content": "", "heading": "at Christmas: vào giáng sinh"}, {"content": "", "heading": "at weekend"}, {"content": "", "heading": "at 7 o’clock"}, {"content": "", "heading": "It’s cooler at night and hotter at noon."}, {"content": "", "heading": "I often read newspapers at lunch time."}, {"content": "", "heading": "At midday everyone would go down to Reg’s Café."}, {"content": "", "heading": "I am busy at the moment."}, {"content": "", "heading": "At times, we go out for lunch."}, {"content": "", "heading": "My parents work hard from at dawn to dusk."}, {"content": "", "heading": "The phone rang at the same time you knocked the door."}, {"content": "", "heading": "4. SINCE:"}, {"content": "", "heading": "Cách dùng: Từ khoảng thời gian nhất định trong quá khứ đến hiện tại"}, {"content": "", "heading": "Ví dụ: I have lived here since 1997."}, {"content": "", "heading": "5. FOR:"}, {"content": "", "heading": "Cách dùng: Một khoảng thời gian nhất định tính từ quá khứ đến hiện tại"}, {"content": "", "heading": "Ví dụ: She has been waiting for you for 3 hours."}, {"content": "", "heading": "6. BEFORE:"}, {"content": "", "heading": "Cách dùng: Trước khoảng thời gian"}, {"content": "", "heading": "Ví dụ: I got up before 6am."}, {"content": "", "heading": "7. AFTER:"}, {"content": "", "heading": "Cách dùng: Sau khoảng thời gian"}, {"content": "", "heading": "Ví dụ: Don’t come back home after 10pm."}, {"content": "", "heading": "8. FROM.. TO:"}, {"content": "", "heading": "Cách dùng: Từ ... đến"}, {"content": "", "heading": "Ví dụ: I worked for the company from 2000 to 2007."}, {"content": "", "heading": "9. TILL/ UNTIL:"}, {"content": "", "heading": "Cách dùng: Đến, cho đến"}, {"content": "", "heading": "Ví dụ: I will wait here until you come back."}, {"content": "", "heading": "10. BY:"}, {"content": "", "heading": "Cách dùng: Vào, tính tới"}, {"content": "", "heading": "Ví dụ: By last month, they had published more than 30 reference books."}, {"content": "", "heading": "11. BETWEEN.. AND:"}, {"content": "", "heading": "Cách dùng: Giữa... và"}, {"content": "", "heading": "Ví dụ: He promised to turn up between 8 am and 10 am."}, {"content": "", "heading": "12. DURING:"}, {"content": "", "heading": "Cách dùng: Trong suốt"}, {"content": "", "heading": "Ví dụ: During the lesson, all of us kept silent."}, {"content": "", "heading": "2. Giới từ chỉ vị trí"}, {"content": "", "heading": "1. IN:"}, {"content": "Dùng trong một khu vực, khoảng không (mang nghĩa là trong)\\nDùng trước cách địa danh như thị trấn, thành phố, quốc gia\\nDùng trước các danh từ chỉ phương hướng\\nDùng trong một số cụm từ:\\nin the middle of: ở giữa\\nin front of: ở trước\\nin the back of: ở phía sau", "heading": "Cách dùng:"}, {"content": "", "heading": "Ví dụ:"}, {"content": "", "heading": "in the bedroom: trong phòng ngủ"}, {"content": "", "heading": "in hospital: trong bệnh viện"}, {"content": "", "heading": "in the rain: trong cơn mưa"}, {"content": "", "heading": "in a town"}, {"content": "", "heading": "in Hanoi"}, {"content": "", "heading": "in Vietnam"}, {"content": "", "heading": "in the west/east/north/south..."}, {"content": "", "heading": "2. AT:"}, {"content": "Dùng trước các địa điểm cụ thể (ở/tại)\\nDùng trong một số cụm từ:\\nat the end of: cuối của\\nat the beginning of: đầu của\\nat the top of: đỉnh của\\nat the bottom of: đáy của\\nat the age of: ở độ tuổi\\nat the center of: giữa của", "heading": "Cách dùng:"}, {"content": "", "heading": "Ví dụ:"}, {"content": "", "heading": "at the airport, at the park, at the cinema, at the station, at the bus stop, at the meeting, at home..."}, {"content": "", "heading": "3. ON:"}, {"content": "Chỉ vị trí trên một bề mặt (trên/ở trên)\\nChỉ vị trí trên các tầng nhà\\nDùng trong một số cụm từ:\\non the left/right (of): bên trái/phải (của)", "heading": "Cách dùng:"}, {"content": "", "heading": "Ví dụ:"}, {"content": "", "heading": "on the table, on the wall, on the beach"}, {"content": "", "heading": "on the second floor"}, {"content": "", "heading": "4. BY/NEXT TO/BESIDE:"}, {"content": "", "heading": "Cách dùng: Dùng với nghĩa là gần/bên cạnh"}, {"content": "", "heading": "Ví dụ: My house is next to/beside/by a school."}, {"content": "", "heading": "5. UNDER:"}, {"content": "", "heading": "Cách dùng: Dùng với nghĩa là bên dưới"}, {"content": "", "heading": "Ví dụ: The children are playing under the trees."}, {"content": "", "heading": "6. BELOW:"}, {"content": "", "heading": "Cách dùng: Thấp hơn cái khác nhưng cao hơn mặt đất"}, {"content": "", "heading": "Ví dụ: The fish are below the surface."}, {"content": "", "heading": "7. OVER:"}, {"content": "bị bao phủ bởi cái khác\\nnhiều hơn", "heading": "Cách dùng:"}, {"content": "", "heading": "Ví dụ:"}, {"content": "", "heading": "put a jacket over your shirt"}, {"content": "", "heading": "over 16 years of age"}, {"content": "", "heading": "8. ABOVE:"}, {"content": "", "heading": "Cách dùng: Dùng với ý nghĩa: vị trí cao hơn một cái gì đó"}, {"content": "", "heading": "Ví dụ: a path above the lake"}, {"content": "", "heading": "9. AMONG:"}, {"content": "", "heading": "Cách dùng: Dùng với nghĩa là: ở giữa (hơn 2 người/ 2 vật)"}, {"content": "", "heading": "Ví dụ: She is among the crowd of fans."}, {"content": "", "heading": "10. BETWEEN:"}, {"content": "", "heading": "Cách dùng: Dùng với nghĩa là: ở giữa (2 người/ 2 vật)"}, {"content": "", "heading": "Ví dụ: He is sitting between his girlfriend and his sister."}, {"content": "", "heading": "11. BEHIND:"}, {"content": "", "heading": "Cách dùng: Dùng với nghĩa là: ở phía sau"}, {"content": "", "heading": "Ví dụ: Behind my house is a river."}, {"content": "", "heading": "12. OPPOSITE:"}, {"content": "", "heading": "Cách dùng: Dùng với nghĩa là: đối diện"}, {"content": "", "heading": "Ví dụ: My school is opposite a hotel."}, {"content": "", "heading": "3. Giới từ chỉ sự chuyển động"}, {"content": "", "heading": "1. ACROSS:"}, {"content": "", "heading": "Cách dùng: Dùng với ý nghĩa: vượt qua, băng qua về phía bên kia"}, {"content": "", "heading": "Ví dụ: The blind man is trying to walk across the crowded street."}, {"content": "", "heading": "2. INTO:"}, {"content": "", "heading": "Cách dùng: Dùng với nghĩa là: vào trong"}, {"content": "", "heading": "Ví dụ: A strange man came into the building this morning."}, {"content": "", "heading": "3. TOWARDS:"}, {"content": "", "heading": "Cách dùng: Dùng với nghĩa là: di chuyển về hướng"}, {"content": "", "heading": "Ví dụ: He went 5 steps towards the house."}, {"content": "", "heading": "4. ALONG:"}, {"content": "", "heading": "Cách dùng: Dùng với nghĩa là: dọc theo"}, {"content": "", "heading": "Ví dụ: She was walking along the beach."}, {"content": "", "heading": "5. BY:"}, {"content": "", "heading": "Cách dùng: Dùng với nghĩa là: ngang qua"}, {"content": "", "heading": "Ví dụ: I usually walk by the park."}, {"content": "", "heading": "6. OVER:"}, {"content": "", "heading": "Cách dùng: Dùng với nghĩa là: vượt qua một cái gì đó"}, {"content": "", "heading": "Ví dụ:"}, {"content": "", "heading": "He walked over the bridge."}, {"content": "", "heading": "The thief climbed over the wall."}, {"content": "", "heading": "7. FROM ... TO:"}, {"content": "", "heading": "Cách dùng: Dùng với nghĩa là: từ ... đến"}, {"content": "", "heading": "Ví dụ: It takes me 30 minutes to travel from my house to school."}, {"content": "", "heading": "8. ROUND / AROUND:"}, {"content": "", "heading": "Cách dùng: Dùng với nghĩa là: quanh"}, {"content": "", "heading": "Ví dụ: If you are free, I will show you round the city."}, {"content": "", "heading": "9. THROUGH:"}, {"content": "", "heading": "Cách dùng: Dùng với nghĩa là: xuyên qua"}, {"content": "", "heading": "Ví dụ: He walked through the forests."}, {"content": "", "heading": "10. OUT OF:"}, {"content": "", "heading": "Cách dùng: Dùng với nghĩa là: ra khỏi"}, {"content": "", "heading": "Ví dụ: Please get out of my room."}, {"content": "", "heading": "11. UP >< DOWN:"}, {"content": "", "heading": "Cách dùng: Dùng với nghĩa là: lên >< xuống"}, {"content": "", "heading": "Ví dụ: He often runs up the stairs for exercise."}, {"content": "", "heading": "4. Giới từ chỉ thể cách"}, {"content": "", "heading": "1. WITH:"}, {"content": "", "heading": "Nghĩa: với"}, {"content": "", "heading": "Ví dụ: I’m shopping with my brother."}, {"content": "", "heading": "2. WITHOUT:"}, {"content": "", "heading": "Nghĩa: không, không có"}, {"content": "", "heading": "Ví dụ: If you come late, we will go without you."}, {"content": "", "heading": "3. ACCORDING TO:"}, {"content": "", "heading": "Nghĩa: theo như"}, {"content": "", "heading": "Ví dụ: According to the archives, he was born in Paris."}, {"content": "", "heading": "4. IN SPITE OF:"}, {"content": "", "heading": "Nghĩa: mặc dù"}, {"content": "", "heading": "Ví dụ: In spite of the rain, he turned up on time."}, {"content": "", "heading": "5. INSTEAD OF:"}, {"content": "", "heading": "Nghĩa: thay vì"}, {"content": "", "heading": "Ví dụ: I’ll have coffee instead of tea."}, {"content": "", "heading": "6. LIKE:"}, {"content": "", "heading": "Nghĩa: giống như"}, {"content": "", "heading": "Ví dụ: He walked like an old man."}, {"content": "", "heading": "IV. Những cấu trúc giới từ thông dụng"}, {"content": "", "heading": "1. ABOUT:"}, {"content": "", "heading": "Cấu trúc - Nghĩa:"}, {"content": "", "heading": "To be doubtful about st: hoài nghi về cái gì"}, {"content": "", "heading": "To be excited about st: hứng thú về cái gì"}, {"content": "", "heading": "To be enthusiastic about st: nhiệt tình, hào hứng về cái gì"}, {"content": "", "heading": "To be sad about st: buồn về cái gì"}, {"content": "", "heading": "To be serious about: nghiêm túc về"}, {"content": "", "heading": "To be reluctant about st (or to) st: ngần ngại, hững hờ với cái gì"}, {"content": "", "heading": "To be uneasy about st: không thoải mái"}, {"content": "To be sorry about st - lấy làm tiếc, hối tiếc về cái gì\\nTo be curious about st - tò mò về cái gì\\nTo be careful about st - cẩn thận về cái gì\\nTo be careless about st - bất cẩn về cái gì\\nTo be confused about st - nhầm lẫn về cái gì", "heading": "To be worried about st: lo lắng về cái gì"}, {"content": "", "heading": "2. AT:"}, {"content": "", "heading": "To be amazed at st: kinh ngạc, sửng sốt vì cái gì"}, {"content": "", "heading": "To be amused at st: thích thú với cái gì"}, {"content": "", "heading": "To be angry at sb: tức giận với ai"}, {"content": "", "heading": "To be annoyed at sb: bực mình với ai"}, {"content": "", "heading": "To be bad at st: yếu kém về cái gì"}, {"content": "", "heading": "To be brilliant at: thông minh, có tài"}, {"content": "", "heading": "To be good/clever at st: giỏi/sắc sảo về cái gì"}, {"content": "", "heading": "To be efficient at st: có năng lực về cái gì"}, {"content": "", "heading": "To be expert at st: thành thạo về cái gì"}, {"content": "", "heading": "To be mad at sb: tức điên lên với ai"}, {"content": "", "heading": "To be present at: có mặt"}, {"content": "", "heading": "To be skillful at st: khéo léo cái gì"}, {"content": "", "heading": "To be surprised at st: ngạc nhiên với"}, {"content": "", "heading": "To be quick at st: bén về cái gì/nhanh chóng làm gì"}, {"content": "", "heading": "3. FOR:"}, {"content": "", "heading": "To be available for sth: có sẵn (cái gì)"}, {"content": "", "heading": "To be bad for: xấu cho"}, {"content": "", "heading": "To be good for: tốt cho"}, {"content": "", "heading": "To be convenient for: thuận lợi cho..."}, {"content": "", "heading": "To be difficult for: khó..."}, {"content": "", "heading": "To be dangerous for: nguy hiểm..."}, {"content": "", "heading": "To be eager for: háo hức cho"}, {"content": "", "heading": "To be eligible for: đủ tư cách cho"}, {"content": "", "heading": "To be late for: trễ..."}, {"content": "", "heading": "To be liable for sth: có trách nhiệm về pháp lý"}, {"content": "", "heading": "To leave for: rời khỏi đâu"}, {"content": "", "heading": "To be famous/well-known for: nổi tiếng"}, {"content": "", "heading": "To be fit for: thích hợp với"}, {"content": "", "heading": "To be greedy for: tham lam..."}, {"content": "", "heading": "To be grateful for sth: biết ơn về việc..."}, {"content": "", "heading": "To be helpful/useful for: có ích/có lợi"}, {"content": "", "heading": "To be necessary for: cần thiết"}, {"content": "", "heading": "To be perfect for: hoàn hảo"}, {"content": "", "heading": "To be prepare for: chuẩn bị cho"}, {"content": "", "heading": "To be qualified for: có phẩm chất"}, {"content": "", "heading": "To be ready for sth: sẵn sàng cho việc gì"}, {"content": "", "heading": "To be responsible for sth: có trách nhiệm về việc gì"}, {"content": "", "heading": "To be suitable for: thích hợp"}, {"content": "", "heading": "To be sorry for: xin lỗi/lấy làm tiếc cho cái gì"}, {"content": "", "heading": "To apologize for st/doing st: xin lỗi vì cái gì/vì đã làm gì"}, {"content": "", "heading": "To thank sb for st/doing st: cảm ơn ai vì cái gì"}, {"content": "", "heading": "To be useful for: có ích, hữu dụng"}, {"content": "", "heading": "4. FROM:"}, {"content": "", "heading": "To borrow st from sb/st: vay mượn của ai/cái gì"}, {"content": "", "heading": "To demand st from sb: đòi hỏi cái gì ở ai"}, {"content": "", "heading": "To draw st from st: rút cái gì"}, {"content": "", "heading": "To emerge from st: nhú lên cái gì"}, {"content": "", "heading": "To escape from: thoát ra từ cái gì"}, {"content": "", "heading": "To be free from: không bị, không phải"}, {"content": "", "heading": "To prevent st from: ngăn cản ai cái gì"}, {"content": "", "heading": "To protect sb/st from: bảo vệ ai/bảo vệ cái gì"}, {"content": "", "heading": "To prohibit sb from doing st: cấm ai làm việc gì"}, {"content": "", "heading": "To separate st/sb from st/sb: tách cái gì ra khỏi cái gì/tách ai ra khỏi ai"}, {"content": "", "heading": "To suffer from: chịu đựng đau khổ"}, {"content": "", "heading": "To be away from st/sb: xa cách cái gì/ai"}, {"content": "", "heading": "To be different from st: khác về cái gì"}, {"content": "", "heading": "To be far from sb/st: xa cách ai/cái gì"}, {"content": "", "heading": "To be safe from st: an toàn trong cái gì"}, {"content": "", "heading": "To save sb/st from: cứu ai/cái gì khỏi"}, {"content": "", "heading": "To be resulting from st: do cái gì có kết quả"}, {"content": "", "heading": "5. IN:"}, {"content": "", "heading": "To be absorbed in: say mê, say sưa"}, {"content": "", "heading": "To believe in st/sb: tin tưởng cái gì/vào ai"}, {"content": "", "heading": "To delight in st: hồ hởi về cái gì"}, {"content": "", "heading": "To be engaged in st: tham dự, lao vào cuộc"}, {"content": "", "heading": "To be experienced in st: có kinh nghiệm về cái gì"}, {"content": "", "heading": "To include st in st: gộp cái gì vào cái gì"}, {"content": "", "heading": "To indulge in st: chìm đắm trong cái gì"}, {"content": "", "heading": "To be interested in st/doing st: quan tâm cái gì/việc gì"}, {"content": "", "heading": "To invest st in st: đầu tư cái gì vào cái gì"}, {"content": "", "heading": "To involved in st: dính líu vào cái gì"}, {"content": "", "heading": "To persist in st: kiên trì trong cái gì"}, {"content": "", "heading": "To be deficient in st: thiếu hụt cái gì"}, {"content": "", "heading": "To be fortunate in st: may mắn trong cái gì"}, {"content": "", "heading": "To be rich in st: dồi dào, phong phú"}, {"content": "", "heading": "To be successful/succeed in: thành công"}, {"content": "", "heading": "6. OF:"}, {"content": "", "heading": "To be ashamed of: xấu hổ về..."}, {"content": "", "heading": "To be afraid of: sợ, e ngại..."}, {"content": "", "heading": "To be ahead of: trước"}, {"content": "", "heading": "To be aware of: nhận thức"}, {"content": "", "heading": "To be capable of: có khả năng"}, {"content": "", "heading": "To be confident of: tự tin"}, {"content": "", "heading": "To be certain of: chắc chắn về"}, {"content": "", "heading": "To be doubtful of: nghi ngờ"}, {"content": "", "heading": "To be fond of: thích"}, {"content": "", "heading": "To be full of: đầy"}, {"content": "", "heading": "To be hopeful of: hi vọng"}, {"content": "", "heading": "To be independent of: độc lập"}, {"content": "", "heading": "To be proud of: tự hào"}, {"content": "", "heading": "To be jealous of: ganh tị với"}, {"content": "", "heading": "To be guilty of: phạm tội về, có tội"}, {"content": "", "heading": "To be innocent of: vô tội"}, {"content": "", "heading": "To remind sb of: gợi cho ai nhớ tới"}, {"content": "", "heading": "To be sick of: chán nản về"}, {"content": "", "heading": "To be scare of: sợ hãi"}, {"content": "", "heading": "To be short of: thiếu"}, {"content": "", "heading": "To be suspicious of: nghi ngờ về"}, {"content": "", "heading": "To be joyful of: vui mừng về"}, {"content": "", "heading": "To be typical of: tiêu biểu, điển hình"}, {"content": "", "heading": "To be tired of: mệt mỏi"}, {"content": "", "heading": "To be terrified of: khiếp sợ về"}, {"content": "", "heading": "7. ON:"}, {"content": "", "heading": "To be dependent/ depend on st/sb: lệ thuộc vào cái gì/vào ai"}, {"content": "", "heading": "To be keen on st: mê cái gì"}, {"content": "", "heading": "To be based on st: dựa trên, dựa vào"}, {"content": "", "heading": "8. TO:"}, {"content": "", "heading": "To be able to: có thể"}, {"content": "", "heading": "To be acceptable to: có thể chấp nhận"}, {"content": "", "heading": "To be accessible to: có thể kết nối, tiếp cận"}, {"content": "", "heading": "To be accustomed to: quen với"}, {"content": "", "heading": "To be agreeable to: có thể đồng ý"}, {"content": "", "heading": "To be addicted to: đam mê"}, {"content": "", "heading": "To be available to sb: sẵn cho ai"}, {"content": "", "heading": "To be clear to: rõ ràng"}, {"content": "", "heading": "To be contrary to: trái lại, đối lập"}, {"content": "", "heading": "To be delightful to sb: thú vị đối với ai"}, {"content": "", "heading": "To be equal to: tương đương với"}, {"content": "", "heading": "To be exposed to: phơi bày, để lộ"}, {"content": "", "heading": "To be familiar to sb: quen thuộc đối với ai"}, {"content": "", "heading": "To be favorable to: tán thành, ủng hộ"}, {"content": "", "heading": "To be grateful to sb: biết ơn ai"}, {"content": "", "heading": "To be harmful to sb/st: có hại cho ai (cho cái gì)"}, {"content": "", "heading": "To be important to: quan trọng"}, {"content": "", "heading": "To be indifferent to: bàng quan, thờ ơ"}, {"content": "", "heading": "To be identical to: giống hệt"}, {"content": "", "heading": "To be kind to sb: tốt với ai"}, {"content": "", "heading": "To be kind of sb: lòng tốt của ai"}, {"content": "", "heading": "To be likely to: có thể"}, {"content": "", "heading": "To be lucky to: may mắn"}, {"content": "", "heading": "To be loyal to: chung thuỷ với"}, {"content": "", "heading": "To be necessary to sth/sb: cần thiết cho việc gì / cho ai"}, {"content": "", "heading": "To be next to: kế bên"}, {"content": "", "heading": "To be open to: cởi mở"}, {"content": "", "heading": "To be opposed to: phản đối"}, {"content": "", "heading": "To be pleasant to: hài lòng"}, {"content": "", "heading": "To be preferable to: đáng thích hơn"}, {"content": "", "heading": "To be profitable to: có lợi"}, {"content": "", "heading": "To be responsible to sb: có trách nhiệm với ai"}, {"content": "", "heading": "To be rude to: thô lỗ, cộc cằn"}, {"content": "", "heading": "To be similar to: giống, tương tự"}, {"content": "", "heading": "To be useful to sb: có ích cho ai"}, {"content": "", "heading": "To be willing to: sẵn lòng"}, {"content": "", "heading": "9. WITH:"}, {"content": "", "heading": "To be acquainted with: quen biết, quen thân"}, {"content": "", "heading": "To be angry with sb: tức giận với ai"}, {"content": "", "heading": "To be busy with st/doing st: bận với cái gì/làm việc gì"}, {"content": "", "heading": "To be bored with = to be fed up with: chán ngán, chán ngấy"}, {"content": "", "heading": "To be consistent with st: kiên trì chung thuỷ với cái gì"}, {"content": "", "heading": "To be content with st = to be satisfied with: hài lòng với"}, {"content": "", "heading": "To be crowded with: đầy, đông đúc"}, {"content": "", "heading": "To be covered with: bao phủ với"}, {"content": "", "heading": "To be cope with: đương đầu với"}, {"content": "", "heading": "To deal with: xử lí, giải quyết với"}, {"content": "", "heading": "To be disappointed with: thất vọng với"}, {"content": "", "heading": "To be patient with st: kiên trì với cái gì"}, {"content": "", "heading": "To be impressed with/by: có ấn tượng/xúc động với"}, {"content": "", "heading": "To be popular with: phổ biến, quen thuộc với"}, {"content": "", "heading": "To be wrong with: có vấn đề với"}]}	ACTIVE	GRAMMAR	GIỚI TỪ - PREPOSITIONS	\N
66d25e2e-808c-4faf-a033-9c4455e53234	a8efe662-9202-4e83-822d-808656858e3e	LIÊN TỪ - CONJUNCTIONS	4	{"title": "LÝ THUYẾT LIÊN TỪ", "sections": [{"content": "", "heading": "LÝ THUYẾT LIÊN TỪ - CONJUNCTIONS"}, {"content": "", "heading": "A. LÍ THUYẾT"}, {"content": "Liên từ là từ vựng sử dụng để liên kết hai từ, cụm từ, mệnh đề hoặc câu lại với nhau. Liên từ được chia thành ba loại:", "heading": "I. Định nghĩa và phân loại liên từ"}, {"content": "Dùng loại liên từ này để nối các từ loại hoặc cụm từ/nhóm từ cùng một loại, hoặc những mệnh đề ngang hàng nhau (tính từ với tính từ, danh từ với danh từ...).\\nLiên từ thuộc nhóm này gồm có: for, and, nor, but, or, yet, so", "heading": "1. Liên từ kết hợp (coordinating conjunctions)"}, {"content": "Một vài liên từ thường kết hợp với các từ khác để tạo thành các tương liên từ. Chúng thường được sử dụng theo cặp để liên kết các cụm từ hoặc mệnh đề có chức năng tương đương nhau về mặt ngữ pháp.\\nLiên từ thuộc nhóm này gồm có:\\nboth... and... (vừa... vừa...), not only... but also... (không những... mà còn...), either... or (hoặc ...hoặc...), neither... nor (không... cũng không...), whether... or (dù ... hay...), as/so... as (như là, bằng/không bằng, không như), no sooner... than... hoặc hardly/scarcely/barely... when (vừa mới... thì...), so/such... that (đến mức... đến nỗi)", "heading": "2. Liên từ tương quan (correlative conjunctions)"}, {"content": "Loại liên từ phụ thuộc nối kết các nhóm từ, cụm từ hoặc mệnh đề có chức năng khác nhau, nối mệnh đề phụ với mệnh đề chính trong câu.\\nLiên từ thuộc nhóm này gồm:\\nafter (sau khi), as/when (khi), as soon as (ngay khi), before (trước khi), just as (vừa lúc), once (một khi), since (từ khi), until/till (cho đến khi), while (trong khi), because/now that/ since/as/seeing that (vì), so (vì vậy), therefore/thus/hence/consequently (do đó, do vậy), so that/in order that (để mà), for fear that/lest (vì e rằng), although/even though/though (mặc dù), however/nevertheless/nonetheless (tuy nhiên), whereas/on the contrary/in contrast/on the other hand (trái lại, trái với), in other words (nói cách khác), as long as/so long as/ providing that/provided that (với điều kiện là, miễn là), or else/otherwise (hoặc là), in the event that/in case (phòng khi), suppose/supposing that (giả sử), if (nếu như), unless (trừ khi), even if (kể cả khi), as if/as though (như thể là), ...", "heading": "3. Liên từ phụ thuộc (subordinating conjunctions)"}, {"content": "", "heading": "II. Cách sử dụng của liên từ"}, {"content": "ALTHOUGH/EVEN THOUGH/THOUGH có nghĩa là “mặc dù... nhưng” dùng để biểu thị hai hành động trái ngược nhau.", "heading": "1. Cách sử dụng của ALTHOUGH/EVEN THOUGH/THOUGH"}, {"content": "", "heading": "Cấu trúc:"}, {"content": "(Lưu ý: ALTHOUGH/EVEN THOUGH/THOUGH đã có nghĩa là “mặc dù... nhưng” nên không được dùng “but” ở đầu mệnh đề sau.)", "heading": "ALTHOUGH/EVEN THOUGH/THOUGH + CLAUSE (S + V), CLAUSE (S + V)"}, {"content": "", "heading": "Ta có:"}, {"content": "", "heading": "ALTHOUGH/EVEN THOUGH/THOUGH + CLAUSE (S + V), CLAUSE (S + V)"}, {"content": "", "heading": "= IN SPITE OF/ DESPITE + CỤM DANH TỪ/V-ING, CLAUSE (S + V)"}, {"content": "Although the weather was awful, we decided to go camping.", "heading": "Ví dụ:"}, {"content": "(Mặc dù thời tiết xấu, chúng tôi vẫn quyết định đi cắm trại.)\\nAlthough she tried her best to pass the exam, she didn’t succeed in it.", "heading": "= In spite of the awful weather, we decided to go camping."}, {"content": "(Mặc dù đã cố gắng hết sức thi đỗ kì thi nhưng cô ấy vẫn không thành công.)", "heading": "= Despite trying her best to pass the exam, she didn’t succeed in it."}, {"content": "Nếu hai mệnh đề của “although/even though/ though” mà đồng chủ ngữ thì sau “in spite of/ despite” là V-ing.\\nNếu hai mệnh đề của “although/even though/ though” mà không đồng chủ ngữ thì sau “in spite of/despite” là cụm danh từ.", "heading": "* Cách đổi từ “although/even though/ though” sang “in spite of/despite” và ngược lại"}, {"content": "Trong một số trường hợp ta có thể dùng “in spite of/despite + the fact that + clause, clause”.", "heading": "Cụm danh từ = a/an/the/my/his/ her/ your/ our/ their/ its + (adv) + (adj) + N"}, {"content": "Although he got up early, he was late for the first train.\\nIn spite ........................................................................................................................................\\nTrong câu này, hai vế của “although” cùng chủ ngữ là “he” nên sau “in spite of + V-ing”. Do đó, câu này sẽ được viết lại như sau:\\nIn spite of getting up early, he was late for the first train.\\nAlthough her grades are bad, she will be admitted to the university.\\nDespite..........................................................................................................................................", "heading": "Ví dụ:"}, {"content": "2. Cách sử dụng của BECAUSE\\nBECAUSE có nghĩa là “bởi vì”, diễn tả mối quan hệ nguyên nhân, kết quả.\\nCông thức:", "heading": "Trong câu này, hai vế của “although” không cùng chủ ngữ nên sau “despite + cụm danh từ”. Do đó, câu này sẽ được viết lại như sau: Despite her bad grades, she will be admitted to the university."}, {"content": "", "heading": "BECAUSE /FOR/AS /SINCE /IN THAT/ NOW THAT/ SEEING THAT + CLAUSE, CLAUSE"}, {"content": "Ví dụ:\\n+ Because the road was icy, many accidents happened.\\n= Because of the icy road, many accidents happened. (Bởi vì đường trơn nên nhiều tai nạn đã xảy ra.)\\n+ Because she was angry, she lost her temper and hurt his feeling.\\n= Because of being angry, she lost her temper and hurt his feeling. (Bởi vì tức giận, cô ấy đã mất bình tĩnh và làm tổn thương anh ấy.)", "heading": "= BECAUSE OF/ OWING TO/ DUE TO/ ON ACCOUNT OF/ AS A RESULT OF + CỤM DANH TỪ/V-ING, CLAUSE"}, {"content": "", "heading": "3. Cách sử dụng của SO... THAT/SUCH... THAT"}, {"content": "", "heading": "SO... THAT/SUCH... THAT có nghĩa là “... đến mức..., đến nỗi...”, diễn tả mối quan hệ nhân quả."}, {"content": "", "heading": "Công thức"}, {"content": "", "heading": "S + V + SO + ADJ/ADV + THAT + CLAUSE"}, {"content": "", "heading": "= S + V + SO + ADJ + A/AN + N + THAT + CLAUSE"}, {"content": "", "heading": "= S + V + SUCH + (A/AN) + ADJ + N + THAT + CLAUSE"}, {"content": "She is so beautiful that many boys run after her. = She is so beautiful a girl that many boys run after her. = She is such a beautiful girl that many boys run after her. (Cô ấy xinh đến nỗi mà rất nhiều chàng trai theo đuổi cô ấy.)\\nThe water is so hot that I can't drink it. = It is such hot water that I can't drink it. (Nước nóng đến mức mà tôi không thể uống được.)", "heading": "Ví dụ:"}, {"content": "Nếu danh từ trong mệnh đề “such... that” là danh từ số nhiều hoặc danh từ không đếm được thì ta không sử dụng “a/an” sau “such... that”.", "heading": "* Lưu ý:"}, {"content": "", "heading": "Ngoài công thức trên, ta còn có công thức: S + V + SO + MANY /MUCH + N + THAT + CLAUSE = S + V + SUCH + A LOT OF + N + THAT + CLAUSE"}, {"content": "I have so much homework that I can't go out with you tonight. = I have such a lot of homework that I can't go out with you tonight. (Tôi có nhiều bài tập về nhà đến mức mà tôi không thể đi chơi với bạn tối nay.)\\nThere are so many stars in the sky that we can't count them. = There are such a lot of stars in the sky that we can't count them. (Có nhiều ngôi sao trên bầu trời đến mức mà chúng ta không thể đếm hết được.)", "heading": "Ví dụ:"}, {"content": "", "heading": "* Cấu trúc TOO/ENOUGH S + V + TOO + ADJ/ADV + (FOR SB) + TO V: quá cho ai đó để làm gì"}, {"content": "", "heading": "Ví dụ: She is too lazy to make progress in study. (Cô ấy quá lười biếng để có tiến bộ trong học tập.) The coffee is too strong for me to drink. (Cà phê quá đặc cho tôi uống.)"}, {"content": "", "heading": "S + V + ADJ/ADV + ENOUGH + (FOR SB) + TO V: đủ cho ai đó để làm gì"}, {"content": "LƯU Ý: + Các biến đổi giữa cấu trúc TOO VÀ ENOUGH: Khi viết từ cấu trúc TOO về ENOUGH hoặc từ ENOUGH về TOO phải đảm bảo có sự đối ngược nhau về thể của động từ và tính từ của hai câu phải trái nghĩa nhau.", "heading": "Ví dụ: She isn't old enough to understand the problem. (Con bé chưa đủ tuổi để hiểu được vấn đề này.)"}, {"content": "", "heading": "Ví dụ: The sea is too dirty for us to swim in. => The sea isn’t clean enough for us to swim in."}, {"content": "", "heading": "+ Các biến đổi giữa TOO về SO... THAT:"}, {"content": "", "heading": "Công thức: S + V + TOO + ADJ/ADV + (FOR SB) + TO V = S + V + SO + ADJ/ADV + THAT + S + CAN'T/COULDN'T + V + O"}, {"content": "The weather was too awful for us to go on a picnic. => The weather was so awful that we couldn't go on a picnic.\\nDưới đây là nội dung văn bản được quét từ hình ảnh của bạn, giữ nguyên định dạng và các lưu ý quan trọng:", "heading": "Ví dụ: He is too intelligent to solve all the problems. => He is so intelligent that he can solve all the problems."}, {"content": "", "heading": "4. Cách sử dụng của EITHER... OR/NEITHER... NOR/ NOT ONLY... BUT ALSO/ BOTH... AND"}, {"content": "", "heading": "a. EITHER... OR (hoặc... hoặc), diễn tả sự lựa chọn khi nó đi với câu khẳng định"}, {"content": "", "heading": "Ví dụ: You can come either today or tomorrow. (Bạn có thể đến vào hôm nay hay mai đều được.)"}, {"content": "", "heading": "b. EITHER... OR (không... không), diễn tả sự phủ định kép khi nó đi với câu phủ định"}, {"content": "", "heading": "= NEITHER... NOR có nghĩa là “không... cũng... không”, diễn tả sự phủ định kép. (Neither... nor: chỉ đi với câu khẳng định)"}, {"content": "She doesn’t want to talk to either me or you.\\n= She wants to talk to neither me nor you.\\n(Cô ấy không muốn nói chuyện với cả tôi và bạn.)", "heading": "Ví dụ:"}, {"content": "", "heading": "* Lưu ý: Với cấu trúc neither... nor / either... or động từ chia theo chủ ngữ gần động từ nhất."}, {"content": "", "heading": "Ví dụ: Neither she nor her children were at home yesterday. (Cả cô ấy và lũ trẻ đều không ở nhà ngày hôm qua.)"}, {"content": "", "heading": "c. NOT ONLY... BUT ALSO = NOT ONLY... BUT... AS WELL: có nghĩa là “không những mà còn”, diễn tả sự lựa chọn kép"}, {"content": "She is not only beautiful but also intelligent. (Cô ấy không những xinh đẹp mà còn thông minh.)\\nNot only she but also her husband came to the party last night. (Không những cô ấy mà cả chồng cô ấy đều đến bữa tiệc tối qua.)", "heading": "Ví dụ:"}, {"content": "", "heading": "d. BOTH... AND có nghĩa là “cả... và / vừa... vừa”, diễn tả sự lựa chọn kép"}, {"content": "Both she and I are teachers of English in a high school. (Cả cô ấy và tôi đều là giáo viên Tiếng Anh ở một trường cấp ba.)\\nIt is both cold and rainy. (Trời vừa mưa vừa lạnh.)", "heading": "Ví dụ:"}, {"content": "", "heading": "Lưu ý:"}, {"content": "", "heading": "BOTH + S1 + AND + S2 + V (số nhiều)"}, {"content": "", "heading": "= S1 + TOGETHER WITH/ALONG WITH/AS WELL AS/ ACCOMPANIED BY + S2 + V(S1)"}, {"content": "Both my sister and my brother like playing chess = My sister as well as my brother likes playing chess.", "heading": "Ví dụ:"}, {"content": "", "heading": "5. Cách sử dụng của các liên từ khác"}, {"content": "", "heading": "1. AND"}, {"content": "", "heading": "Cách dùng: Thêm, bổ sung thông tin (và)"}, {"content": "", "heading": "Ví dụ: She is rich and famous. (Cô ấy giàu có và nổi tiếng.)"}, {"content": "", "heading": "2. NOR"}, {"content": "", "heading": "Cách dùng: Bổ sung thêm một ý phủ định vào một ý phủ định được nêu trước đó (cũng không)"}, {"content": "", "heading": "Ví dụ: I don't want to call him nor intend to apologize to him. (Tôi không muốn gọi cho anh ấy cũng không có ý định xin lỗi anh ta.)"}, {"content": "", "heading": "3. BUT"}, {"content": "", "heading": "Cách dùng: Diễn tả sự đối lập, ngược nghĩa (nhưng, nhưng mà)"}, {"content": "", "heading": "Ví dụ: She is beautiful but arrogant. (Cô ấy xinh đẹp nhưng kiêu ngạo.)"}, {"content": "", "heading": "4. OR = OR ELSE = OTHERWISE"}, {"content": "", "heading": "Cách dùng: Nêu thêm sự lựa chọn (hoặc là, hay là)"}, {"content": "", "heading": "Ví dụ: Hurry up or else you will miss the last bus. (Nhanh lên hoặc là bạn sẽ nhỡ chuyến xe buýt cuối cùng.)"}, {"content": "", "heading": "5. YET"}, {"content": "", "heading": "Cách dùng: Đưa ra một ý ngược lại so với ý trước đó (vậy mà, thế mà)"}, {"content": "", "heading": "Ví dụ: They are ugly and expensive, yet people buy them. (Chúng xấu và đắt, vậy mà mọi người vẫn mua.)"}, {"content": "", "heading": "6. SO (THEREFORE = THUS = HENCE = CONSEQUENTLY = AS A RESULT)"}, {"content": "", "heading": "Cách dùng: Nêu kết quả của hành động (vì vậy, do đó, do vậy)"}, {"content": "", "heading": "Ví dụ:"}, {"content": "", "heading": "He was ill, so he didn't go to school yesterday. (Anh ấy bị ốm nên hôm qua anh ấy không tới trường.)"}, {"content": "", "heading": "The car in the front stopped so suddenly. Therefore, the accident happened. (Chiếc ô tô đằng trước dừng quá đột ngột, vì vậy vụ tai nạn đã xảy ra.)"}, {"content": "", "heading": "7. RATHER THAN"}, {"content": "", "heading": "Cách dùng: Diễn tả lựa chọn (hơn là)"}, {"content": "", "heading": "Ví dụ: I think you should choose to become a teacher rather than a doctor. (Tôi nghĩ bạn nên chọn trở thành giáo viên hơn là bác sĩ.)"}, {"content": "", "heading": "8. WHETHER ... OR"}, {"content": "", "heading": "Cách dùng: Diễn tả sự thay thế (hay là)"}, {"content": "", "heading": "Ví dụ: I don't know whether he will come or not. (Tôi không biết là anh ấy sẽ đến hay không.)"}, {"content": "", "heading": "9. AS ... AS / SO ... AS"}, {"content": "", "heading": "Cách dùng: So sánh ngang/không ngang bằng (bằng/không ... bằng)"}, {"content": "", "heading": "Ví dụ:"}, {"content": "", "heading": "She is as tall as me. (Cô ấy cao bằng tôi)"}, {"content": "", "heading": "She isn't as/so tall as me. (Cô ấy không cao bằng tôi.)"}, {"content": "", "heading": "10. BARELY ... WHEN / HARDLY ... WHEN / SCARCELY ... WHEN / NO SOONER ... THAN"}, {"content": "", "heading": "Cách dùng: Diễn tả quan hệ thời gian (ngay khi ... thì, vừa mới ... thì)"}, {"content": "", "heading": "Ví dụ: Hardly had he gone to bed when the telephone rang. (Ngay khi anh ấy đi ngủ thì điện thoại kêu.)"}, {"content": "", "heading": "11. AFTER"}, {"content": "", "heading": "Cách dùng: Diễn tả hành động xảy ra sau một hành động khác (sau khi)"}, {"content": "", "heading": "Ví dụ: After he had finished his work, he went out for a drink. (Ngay khi anh ấy xong việc, anh ấy ra ngoài uống nước.)"}, {"content": "", "heading": "12. BEFORE"}, {"content": "", "heading": "Cách dùng: Diễn tả hành động xảy ra trước một hành động khác (trước khi)"}, {"content": "", "heading": "Ví dụ: He had finished his work before he went out for a drink. (Anh ấy đã xong việc trước khi anh ấy ra ngoài uống nước.)"}, {"content": "", "heading": "13. AS SOON AS"}, {"content": "", "heading": "Cách dùng: Chỉ một hành động xảy ra liền ngay sau một hành động khác (ngay khi)"}, {"content": "", "heading": "Ví dụ: As soon as she went home, she had a bath. (Ngay khi cô ấy về nhà, cô ấy đi tắm.)"}, {"content": "", "heading": "14. JUST AS"}, {"content": "", "heading": "Cách dùng: Diễn tả hai hành động xảy ra gần như cùng thời điểm (ngay khi, vừa lúc)"}, {"content": "", "heading": "Ví dụ: He left the meeting just as we arrived. (Anh ta rời khỏi cuộc họp vừa lúc chúng tôi tới đó.)"}, {"content": "", "heading": "15. ONCE"}, {"content": "", "heading": "Cách dùng: Nói về một thời điểm mà ở đó một hành động đã xảy ra hoặc sẽ xảy ra (một khi)"}, {"content": "", "heading": "Ví dụ: Once you have well-prepared for it, you will certainly be successful. (Khi bạn đã chuẩn bị kĩ càng cho nó, thì bạn chắc chắn sẽ thành công.)"}, {"content": "", "heading": "16. UNTIL/TILL"}, {"content": "", "heading": "Cách dùng: Chỉ hành động xảy ra/không xảy ra cho tới một thời điểm nào đó (cho tới khi)"}, {"content": "", "heading": "Ví dụ: I will wait for you until it's possible. (Anh sẽ đợi em đến chừng nào có thể.)"}, {"content": "", "heading": "17. IN OTHER WORDS"}, {"content": "", "heading": "Cách dùng: Để giải thích rõ nghĩa hơn (nói cách khác)"}, {"content": "", "heading": "Ví dụ: He was economical with the truth – in other words, he lied. (Anh ấy tiết kiệm sự thật hay nói cách khác là anh ấy nói dối.)"}, {"content": "", "heading": "18. WHEN"}, {"content": "", "heading": "Cách dùng: Liên kết hai hành động có mối quan hệ về thời gian (khi)"}, {"content": "", "heading": "Ví dụ: When she came, I was cooking dinner. (Khi cô ấy tới, tôi đang nấu bữa tối.)"}, {"content": "", "heading": "19. WHILE = MEANWHILE"}, {"content": "", "heading": "Cách dùng: Chỉ các hành động diễn ra cùng một lúc (trong khi)"}, {"content": "", "heading": "Ví dụ: While I was doing my homework, my mother was cleaning the floor. (Khi tôi đang làm bài tập về nhà thì mẹ tôi đang lau nhà.)"}, {"content": "", "heading": "20. SO THAT = IN ORDER THAT"}, {"content": "", "heading": "Cách dùng: Nêu mục đích hoặc kết quả của hành động có dự tính (để mà)"}, {"content": "", "heading": "Ví dụ: I'm trying my best to study English well so that I can find a better job. (Tôi đang cố gắng hết sức học tiếng Anh để tôi có thể tìm được một công việc tốt hơn.)"}, {"content": "", "heading": "21. FOR FEAR THAT = LEST"}, {"content": "", "heading": "Cách dùng: Chỉ mục đích phủ định (vì e rằng, sợ rằng)"}, {"content": "", "heading": "Ví dụ: He wore dark glasses lest he could be recognized. (Anh ta đeo kính râm vì sợ rằng mình có thể bị nhận ra.)"}, {"content": "", "heading": "22. WHEREAS = ON THE CONTRARY = IN CONTRAST = ON THE OTHER HAND"}, {"content": "", "heading": "Cách dùng: Diễn tả sự ngược nghĩa giữa hai mệnh đề (trong khi)"}, {"content": "", "heading": "Ví dụ: He loves foreign holidays whereas his wife prefers to stay at home. (Anh ấy thích đi du lịch nước ngoài, trái lại vợ anh ấy thì chỉ thích ở nhà.)"}, {"content": "", "heading": "23. AS/SO LONG AS = PROVIDING (THAT) = PROVIDED (THAT)"}, {"content": "", "heading": "Cách dùng: Diễn tả điều kiện (với điều kiện là, miễn là)"}, {"content": "", "heading": "Ví dụ: You can use my bike providing that you promise to give it back tomorrow. (Bạn có thể sử dụng xe đạp của tôi với điều kiện bạn hứa trả lại nó vào ngày mai.)"}, {"content": "", "heading": "24. IN THE EVENT THAT = IN CASE"}, {"content": "", "heading": "Cách dùng: Diễn tả giả định về một hành động có thể xảy ra trong tương lai (trong trường hợp, phòng khi)"}, {"content": "", "heading": "Ví dụ: Take an umbrella in case it rains. (Mang theo ô phòng khi trời mưa.)"}, {"content": "", "heading": "25. SUPPOSE / SUPPOSING (THAT)"}, {"content": "", "heading": "Cách dùng: Dùng để thay thế cho \\"if\\" trong mệnh đề phụ (giả sử)"}, {"content": "", "heading": "Ví dụ: Supposing he hates you, what will you do? (Giả sử anh ấy ghét bạn, bạn sẽ làm gì?)"}, {"content": "", "heading": "26. AS IF/THOUGH"}, {"content": "", "heading": "Cách dùng: Dùng trong giả định (như thể là)"}, {"content": "", "heading": "Ví dụ: He looked frightened as if he had seen a ghost. (Anh ấy trông hoảng sợ như thể anh ấy đã nhìn thấy ma.)"}, {"content": "", "heading": "27. BESIDES / MOREOVER / FURTHERMORE / IN ADDITION"}, {"content": "", "heading": "Cách dùng: Dùng để bổ sung thêm ý/thông tin (Ngoài ra/hơn nữa/thêm vào đó)"}, {"content": "", "heading": "Ví dụ: I can't go now, I'm too busy. Besides, my passport is out of date. (Tôi không thể đi bây giờ; tôi bận lắm. Ngoài ra, hộ chiếu của tôi đã hết hạn rồi.)"}, {"content": "", "heading": "28. FOR EXAMPLE = FOR INSTANCE"}, {"content": "Ví dụ: There are many interesting places to visit in the city. The art museum, for instance, has an excellent collection of modern paintings. (Có nhiều nơi thú vị để đến thăm trong thành phố này. Chẳng hạn như viện bảo tàng nghệ thuật có một bộ sưu tập xuất sắc các bức tranh hiện đại.)", "heading": "Cách dùng: Ví dụ, chẳng hạn như"}, {"content": "", "heading": "29. INDEED = IN FACT"}, {"content": "", "heading": "Cách dùng: Được dùng để nhấn mạnh/xác nhận thông tin trước đó (thực sự, quả thật)"}, {"content": "", "heading": "Ví dụ: I am happy, indeed proud, to be a member of your team. (Tôi rất vui, thực sự là rất tự hào được là một thành viên trong đội của bạn.)"}, {"content": "", "heading": "30. INSTEAD"}, {"content": "", "heading": "Cách dùng: Thay vì, thay vào"}, {"content": "", "heading": "Ví dụ: We didn't go on holiday. We stayed at home, instead. (Chúng tôi đã không đi du lịch. Thay vào đó, chúng tôi ở nhà.)"}]}	ACTIVE	GRAMMAR	LIÊN TỪ - CONJUNCTIONS	\N
76809457-1f04-4656-8b68-2462e528dcb7	135214f4-611e-45a7-a4b8-076794ab24a0	MỆNH ĐỀ QUAN HỆ - RELATIVE CLAUSES	4	{"title": "LÝ THUYẾT MỆNH ĐỀ QUAN HỆ", "sections": [{"content": "", "heading": "LÝ THUYẾT MỆNH ĐỀ QUAN HỆ - RELATIVE CLAUSES"}, {"content": "", "heading": "A. LÍ THUYẾT"}, {"content": "Mệnh đề quan hệ là mệnh đề phụ được nối với mệnh đề chính bởi các đại từ quan hệ (who, whom, whose, which, that) hay các trạng từ quan hệ như (where, when, why). Mệnh đề quan hệ đứng ngay đằng sau danh từ, đại từ trong mệnh đề chính để bổ sung ý nghĩa cho danh từ, đại từ ấy, phân biệt danh từ, đại từ ấy với các danh từ, đại từ khác. Chức năng của nó giống như một tính từ, do vậy nó còn được gọi là mệnh đề tính ngữ.", "heading": "I. Định nghĩa"}, {"content": "", "heading": "II. Các loại đại từ quan hệ"}, {"content": "Là đại từ quan hệ chỉ người, đứng sau danh từ chỉ người để làm chủ ngữ (subject) hoặc tân ngữ (object) cho động từ đứng sau nó. Theo sau who là chủ ngữ hoặc là động từ.\\nVí dụ:\\nThe man who is waiting for the bus is my English teacher.\\n→ (theo sau who là động từ → who đóng vai trò làm chủ ngữ)\\nThe man who I met on the bus yesterday is Phuong's father.\\n→ (theo sau who là chủ ngữ → who đóng vai trò làm tân ngữ)", "heading": "1. Who"}, {"content": "Là đại từ quan hệ chỉ người, đứng sau danh từ chỉ người để làm tân ngữ (object) cho động từ đứng sau nó. Theo sau whom là chủ ngữ.\\nVí dụ:\\nThe man who(m) I met on the bus yesterday is Phuong's father.\\n→ (theo sau whom là chủ ngữ → whom đóng vai trò làm tân ngữ)", "heading": "2. Whom"}, {"content": "Cả who và whom đều là đại từ quan hệ chỉ người, đứng sau danh từ chỉ người. Nhưng who làm cả chủ ngữ và tân ngữ cho động từ đứng sau nó còn whom chỉ làm tân ngữ cho động từ sau nó mà thôi.", "heading": "NHƯ VẬY:"}, {"content": "Là đại từ quan hệ chỉ vật, sự vật, sự việc làm chủ ngữ hoặc tân ngữ cho động từ sau nó. Theo sau which có thể là một động từ hoặc một chủ ngữ.\\nVí dụ:\\nI am reading the book which was written by a famous writer.\\n→ (theo sau which là động từ → which đóng vai trò làm chủ ngữ)\\nI am reading the book which you gave me on my birthday.\\n→ (theo sau which là chủ ngữ → which đóng vai trò làm tân ngữ)", "heading": "3. Which"}, {"content": "Là đại từ quan hệ chỉ cả người lẫn vật, có thể được dùng thay cho Who, Whom, Which trong mệnh đề quan hệ thuộc loại mệnh đề xác định (Restricted Clause).", "heading": "4. That"}, {"content": "", "heading": "a. Luôn dùng that trong những trường hợp sau"}, {"content": "Ví dụ:\\nI saw her and her dog that were walking in the park.", "heading": "+ dùng that thay thế cho những danh từ chỉ cả người lẫn vật"}, {"content": "Ví dụ:\\nMy father is the one that I admire most.\\nAll that is mine is yours.", "heading": "+ dùng that sau các đại từ bất định (someone/body, no one/body, everyone/body, anyone/body; something, everything, anything, nothing) hoặc sau all/much/none, little…"}, {"content": "Ví dụ:\\nMy mother is the most beautiful woman that I have ever known.", "heading": "+ dùng that sau dạng so sánh nhất"}, {"content": "Ví dụ:\\nYou are the only person that I can believe.", "heading": "+ dùng that sau các từ chỉ thứ tự như: first, second, next, … last, only"}, {"content": "It + be + thành phần nhấn mạnh + that + S + V\\nVí dụ:\\nIt was the book that my mother bought me last week.\\nIt is you that I am looking for.\\nIt is/was not until + time/time clause + that + S + V\\n(phải mãi tới khi… thì)\\nVí dụ:\\nIt was not until he was 40 that he got married.", "heading": "+ dùng that trong cấu trúc câu nhấn mạnh"}, {"content": "", "heading": "b. Không được dùng that trong những trường hợp sau"}, {"content": "Ví dụ:\\nShe couldn't go to the party, that makes me sad.\\nA              B              C           D\\n(trong câu này sai ở C vì that không được dùng sau dấu phẩy (,) nên ta sửa lại bằng cách đổi that thành which)", "heading": "+ không dùng that sau dấu phẩy"}, {"content": "Ví dụ:\\nThe music to that I am listening is very sweet and gentle.\\nA              B                    C                              D\\n(trong câu này sai ở B vì that không được dùng sau giới từ (to) nên ta sửa lại bằng cách đổi that thành which)", "heading": "+ không dùng that sau giới từ"}, {"content": "Là đại từ quan hệ chỉ sở hữu. Whose đứng sau danh từ chỉ người hoặc vật và thay cho tính từ sở hữu trước danh từ. Whose luôn đi kèm với một danh từ.\\nVí dụ:\\nI am studying with Tom whose father is a famous doctor.", "heading": "5. Whose"}, {"content": "", "heading": "III. Các trạng từ quan hệ"}, {"content": "Là trạng từ quan hệ chỉ thời gian, đứng sau danh từ chỉ thời gian, dùng thay cho on/at/in + which, then.\\nVí dụ:\\n- I still remember the day when my mother took me to school for the first time.\\n= I still remember the day on which my mother took me to school for the first time.\\n- May is the month when I was born.\\n= May is the month in which I was born.\\n- That was the time when he managed the company.\\n= That was the time at which he managed the company.", "heading": "1. When"}, {"content": "Là trạng từ quan hệ chỉ nơi chốn, đứng sau danh từ chỉ nơi chốn, thay cho at/on/in + which, there.\\nVí dụ:\\nThat is the house where we used to live.\\n= That is the house in which we used to live.", "heading": "2. Where"}, {"content": "Là trạng từ quan hệ chỉ lí do, đứng sau tiền ngữ \\"the reason\\", dùng thay cho \\"for which\\".\\nVí dụ:\\nPlease tell me the reason why you are telling me a lie.\\n= Please tell me the reason for which you are telling me a lie.", "heading": "3. Why"}, {"content": "Có ba loại mệnh đề quan hệ:", "heading": "IV. Các loại mệnh đề quan hệ"}, {"content": "Mệnh đề quan hệ xác định dùng để bổ nghĩa cho danh từ đứng trước, là bộ phận quan trọng của câu, nếu bỏ đi thì mệnh đề chính không có nghĩa rõ ràng.\\nVí dụ:\\n- The girl who is wearing the blue dress is my sister.\\n- The book which I borrowed from you is very interesting.", "heading": "1. Mệnh đề quan hệ xác định (restrictive relative clause)"}, {"content": "- Mệnh đề quan hệ không xác định dùng để bổ nghĩa cho danh từ đứng trước, là phần giải thích thêm, nếu bỏ đi thì mệnh đề chính vẫn còn nghĩa rõ ràng.\\n- Mệnh đề quan hệ không xác định thường được ngăn với mệnh đề chính bởi các dấu phẩy. Danh từ đứng trước thường là tên riêng hoặc trước các danh từ thường có các từ như: this, that, these, those, my, his, her, your, our, their,…\\n- Không được dùng that trong mệnh đề không xác định.\\nVí dụ:\\n- Peter, who is my boyfriend, is very handsome and intelligent.\\n- My father, who is 50 years old, is a doctor.", "heading": "2. Mệnh đề quan hệ không xác định (non-restrictive relative clause)"}, {"content": "Mệnh đề quan hệ nối tiếp dùng để giải thích cả một câu, trường hợp này chỉ dùng đại từ quan hệ which và dùng dấu phẩy để tách hai mệnh đề. Mệnh đề này luôn đứng ở cuối câu.\\nVí dụ:\\nHe sent me a bunch of flowers, which made me surprised.", "heading": "3. Mệnh đề quan hệ nối tiếp"}, {"content": "Mệnh đề quan hệ có thể rút gọn theo bốn cách:", "heading": "V. Mệnh đề quan hệ rút gọn"}, {"content": "- Dùng khi đại từ quan hệ đóng vai trò làm chủ ngữ và động từ trong mệnh đề quan hệ ở thể chủ động.\\n- Ta dùng present participle phrase thay cho mệnh đề đó (bỏ đại từ quan hệ và trợ động từ, đưa động từ chính về nguyên mẫu rồi thêm –ing).\\nVí dụ:\\n- The man who is sitting next to you is my uncle.\\n→ The man sitting next to you is my uncle.\\n- Do you know the man who asked me the way to the bank?\\n→ Do you know the man asking me the way to the bank?", "heading": "1. Using participle phrases (sử dụng hiện tại phân từ - V-ing)"}, {"content": "- Dùng khi đại từ quan hệ đóng vai trò làm chủ ngữ và động từ trong mệnh đề quan hệ ở thể bị động.\\n- Ta dùng past participle phrase thay cho mệnh đề đó (bỏ đại từ quan hệ, trợ động từ và bắt đầu cụm từ bằng past participle).\\nVí dụ:\\nThe students who were punished by the teacher are lazy.\\n→ The students punished by the teacher are lazy.", "heading": "2. Using past participle phrases (sử dụng quá khứ phân từ - Vp2)"}, {"content": "", "heading": "3. Using \\"to infinitive\\" or \\"infinitive phrase\\" (for sb to do)"}, {"content": "Ví dụ:\\n- She was the last person that was interviewed this morning.\\n→ She was the last person to be interviewed this morning.\\n- She is the most suitable person who can take on this job.\\n→ She is the most suitable person to take on this job.", "heading": "a. Khi đại từ quan hệ thay thế cho các từ có chứa số thứ tự như: first, second, next, third… last, only và so sánh nhất"}, {"content": "Ví dụ:\\nThere is a good restaurant where we can eat good food.\\n→ There is a good restaurant for us to eat good food.\\nHere is the form that you must fill in.\\n→ Here is the form for you to fill in.", "heading": "b. Câu bắt đầu bằng: here, there"}, {"content": "Mệnh đề quan hệ không xách định có thể được rút gọn bằng cách dùng cụm danh từ.\\nVí dụ:\\n- Mrs Flora, who is a rich businesswoman, will sponsor our competition.\\n→ Mrs Flora, a rich businesswoman, will sponsor our competition.\\n- I live in Hanoi, which is the capital of Vietnam.\\n→ I live in Hanoi, the capital of Vietnam.\\nLƯU Ý\\nKhi đại từ quan hệ đóng vai trò làm tân ngữ của mệnh đề, ta có thể bỏ đại từ quan hệ đó.\\nVí dụ:\\nThe dress which Trang is wearing is very nice.\\n→ The dress Trang is wearing is very nice.", "heading": "4. Using noun phrases (cụm danh từ)"}, {"content": "Trong văn phong trang trọng, giới từ có thể được đặt trước đại từ quan hệ. Tuy nhiên, ta chỉ đặt giới từ trước hai đại từ quan hệ là whom (cho người) và which (cho vật).\\nVí dụ:\\nThe picture which you are looking at was painted by a famous artist.\\n→ The picture at which you are looking was painted by a famous artist.\\nChú ý:", "heading": "VI. Giới từ trong mệnh đề quan hệ"}, {"content": "", "heading": "- Khi giới từ đứng cuối mệnh đề quan hệ thì ta có thể bỏ đại từ quan hệ và có thể dùng that thay cho whom và which trong mệnh đề quan hệ xác định."}, {"content": "", "heading": "- Khi giới từ đứng trước đại từ quan hệ thì ta không thể bỏ đại từ quan hệ và không thể dùng that thay cho whom và which."}, {"content": "Ví dụ:\\n- Daisy has three brothers, all of whom are married.\\n- I tried on three pairs of shoes, none of which fitted me.\\n- He asked me a lot of questions, most of which I couldn't answer.\\n- There were a lot of people at the meeting, few of whom I had met before.", "heading": "- Cách dùng của các cấu trúc mở đầu cho mệnh đề quan hệ: all, most, none, neither, any, either, some, (a) few, both, half, each, one, two, several, many, much, + of which/whom."}, {"content": "Để kết hợp hai câu thành một câu dùng đại từ quan hệ, ta thực hiện theo các bước sau:", "heading": "VII. Cách kết hợp câu dùng đại từ quan hệ"}, {"content": "", "heading": "Bước 1: Xác định thành phần giống nhau giữa hai mệnh đề."}, {"content": "", "heading": "Bước 2: Đặt đại từ quan hệ ngay sau từ mà nó thay thế ở mệnh đề thứ nhất rồi viết mệnh đề thứ hai trước xong mới viết mệnh đề thứ nhất."}, {"content": "Ví dụ 1:\\nThe man works in the hospital. I told you about him.\\nTa thấy thành phần giống nhau giữa hai mệnh đề này là \\"the man\\" và \\"him\\".\\nThe man là danh từ chỉ người nên ta dùng đại từ quan hệ who hoặc whom và đặt ngay sau the man, sau đó ta viết mệnh đề thứ hai (bỏ him) xong quay lại viết phần còn lại của mệnh đề thứ nhất.\\n→ The man who(m) I told you about works in the hospital.\\nVí dụ 2:\\nThe man was injuried in the accident. He is now in hospital.\\nTa thấy thành phần giống nhau giữa hai mệnh đề này là \\"the man\\" và \\"he\\".\\nHe là chủ ngữ của mệnh đề thứ hai nên ta phải dùng đại từ quan hệ who và đặt ngay sau the man, sau đó ta viết phần còn lại của mệnh đề thứ nhất rồi viết sang mệnh đề thứ hai (bỏ he).\\n→ The man who was injuried in the accident is now in hospital.\\nLưu ý: Câu này không thể viết là The man who is now in hospital was injuried in the accident.\\nVì theo thứ tự của hành động thì hành động bị thương phải xảy ra trước hành động vào viện.", "heading": "Bước 3: Đại từ quan hệ thay thế cho từ gì ở mệnh đề thứ hai thì bỏ từ ấy đi."}]}	ACTIVE	GRAMMAR	MỆNH ĐỀ QUAN HỆ - RELATIVE CLAUSES	\N
614260b1-8d4c-455b-af46-fd33eb73e8d9	40a22bef-8b76-400f-bed3-e5c8869ae71d	N - CÂU HỎI ĐUÔI - TAG QUESTION	1	{"title": "LÝ THUYẾT CÂU HỎI ĐUÔI", "sections": [{"content": "", "heading": "LÝ THUYẾT CÂU HỎI ĐUÔI – TAG QUESTIONS"}, {"content": "Câu hỏi đuôi (tag question) là dạng câu hỏi rất hay được sử dụng trong tiếng Anh, đặc biệt là tiếng Anh giao tiếp. Câu hỏi đuôi là câu hỏi ngắn ở cuối câu trần thuật. Câu hỏi này được dùng khi người nói muốn xác minh thông tin là đúng hay không hoặc khi khuyến khích một sự hồi đáp từ phía người nghe.", "heading": "I. Câu hỏi đuôi là gì?"}, {"content": "", "heading": "Ví dụ: She is learning English now, isn't she? (Cô ấy đang học tiếng Anh bây giờ phải không?)"}, {"content": "", "heading": "II. Công thức"}, {"content": "Nếu câu nói trước dấu phẩy là câu khẳng định, câu hỏi đuôi phải ở thể phủ định (viết tắt).\\nNếu câu nói trước dấu phẩy là câu phủ định, câu hỏi đuôi phải ở thể khẳng định.", "heading": "1. Nguyên tắc chung khi lập câu hỏi đuôi"}, {"content": "", "heading": "Ví dụ: You haven't finished the work, have you? (Bạn chưa xong việc phải không?) You have finished the work, haven't you? (Bạn xong việc rồi phải không?)"}, {"content": "Câu hỏi đuôi gồm một trợ động từ hoặc to be hoặc động từ khuyết thiếu tương ứng với thì được dùng trong câu nói trước dấu phẩy, có NOT hoặc không có NOT và một đại từ nhân xưng tương ứng với chủ ngữ của câu nói trước dấu phẩy.", "heading": "2. Cấu tạo chung của câu hỏi đuôi"}, {"content": "He has closed the window, hasn't he? (Anh ấy đã đóng cửa phải không?)\\nYour mother was born in Hanoi, wasn't she? (Mẹ bạn sinh ra ở Hà Nội phải không?)\\nHe loves you, doesn't he? (Anh ấy thích cậu phải không?)", "heading": "Ví dụ: She is beautiful, isn't she? (Cô ấy xinh phải không?)"}, {"content": "Ta lên giọng với câu hỏi đuôi khi ta không chắc chắn về thông tin trong câu trần thuật câu hỏi đuôi nhằm mục đích xác minh thông tin.", "heading": "III. Ngữ điệu trong câu hỏi đuôi"}, {"content": "Ta xuống giọng với câu hỏi đuôi khi ta chắc chắn về thông tin của câu trần thuật, và ta đang khuyến khích người nghe hồi đáp lại.", "heading": "Ví dụ: He is our new teacher of English, isn't he? (Người đó là giáo viên tiếng Anh mới của chúng ta phải không?)"}, {"content": "", "heading": "Ví dụ: This is your bag, isn't it? (Đấy là túi của bạn phải không?)"}, {"content": "", "heading": "IV. Một số trường hợp cần lưu ý"}, {"content": "", "heading": "1. Câu hỏi đuôi của “I am” là “aren't I”"}, {"content": "", "heading": "Ví dụ: I am very bad, aren't I? (Mình tệ lắm phải không?)"}, {"content": "", "heading": "2. “Let” đầu câu “Let” đầu câu có nhiều dạng cần phân biệt:"}, {"content": "", "heading": "a. “Let” trong câu rủ (let's) thì khi thành lập hỏi đuôi sẽ dùng “shall we?”"}, {"content": "", "heading": "Ví dụ: Let's go out for a drink, shall we? (Chúng mình sẽ đi uống nước phải không?)"}, {"content": "", "heading": "b. “Let” trong câu xin phép (let us/let me) thì khi thành lập hỏi đuôi sẽ dùng “will you?”"}, {"content": "", "heading": "Ví dụ: Let us use the telephone, will you? (Mình sử dụng điện thoại được chứ?)"}, {"content": "", "heading": "c. “Let” trong câu đề nghị giúp người khác (let me) thì khi thành lập hỏi đuôi sẽ dùng “may I?”"}, {"content": "", "heading": "Ví dụ: Let me help you do it, may I? (Hãy để mình giúp bạn làm nó được không?)"}, {"content": "", "heading": "3. Chủ ngữ là “Everyone/Everybody, Someone/Somebody, Anyone/Anybody, No one/Nobody...” câu hỏi đuôi là “they”"}, {"content": "", "heading": "Ví dụ: Everybody has come, haven't they? (Mọi người đến đủ rồi phải không?)"}, {"content": "", "heading": "4. Chủ ngữ là “nothing, everything, something, anything” thì câu hỏi đuôi dùng “it”"}, {"content": "", "heading": "Ví dụ: Everything is fine, isn't it? (Mọi thứ tốt đẹp phải không?)"}, {"content": "", "heading": "5. Trong câu có các trạng từ phủ định và bán phủ định như: never, seldom, hardly, scarcely, little... thì câu đó được xem như là câu phủ định - phần hỏi đuôi sẽ ở dạng khẳng định"}, {"content": "", "heading": "Ví dụ: Our boss never comes late, does he? (Sếp của chúng mình không bao giờ đi muộn phải không?)"}, {"content": "", "heading": "6. Had better Khi thấy had/'d better ta chỉ cần mượn trợ động từ “had” để lập câu hỏi đuôi."}, {"content": "", "heading": "Ví dụ: He'd better apologize, hadn't he? (Tốt hơn hết là anh ấy nên xin lỗi phải không?)"}, {"content": "", "heading": "7. Would rather Khi thấy would/'d rather ta chỉ cần mượn trợ động từ “would” để lập câu hỏi đuôi."}, {"content": "", "heading": "Ví dụ: She'd rather go to the doctor, wouldn't she? (Cô ấy nên đến gặp bác sĩ, đúng không?)"}, {"content": "", "heading": "8. Câu đầu có It seems that + mệnh đề thì ta lấy mệnh đề làm câu hỏi đuôi"}, {"content": "", "heading": "Ví dụ: It seems that you are right, aren't you? (Có vẻ như là cậu đúng phải không?)"}, {"content": "", "heading": "9. Chủ từ là mệnh đề danh từ, dùng “it” trong câu hỏi đuôi"}, {"content": "Why he killed himself seems a secret, doesn't it? (Tại sao anh ấy lại tự sát dường như là một bí mật phải không?)", "heading": "Ví dụ: What she has just said is unreasonable, isn't it? (Điều cô ấy vừa mới nói là phi lý phải không?)"}, {"content": "", "heading": "10. Sau câu mệnh lệnh cách (Do.../Don't do v.v... ), câu hỏi đuôi thường là ... will you?"}, {"content": "Don't be late, will you? (Bạn đừng đến muộn được không?)", "heading": "Ví dụ: Open the door, will you? (Bạn mở cửa ra được không?)"}, {"content": "", "heading": "11. Câu đầu là I wish, dùng “may” trong câu hỏi đuôi"}, {"content": "", "heading": "Ví dụ: I wish to study English, may I? (Tôi muốn học tiếng Anh, có được không?)"}, {"content": "", "heading": "12. Chủ từ là “one”, dùng “you” hoặc “one” trong câu hỏi đuôi"}, {"content": "", "heading": "Ví dụ: When one is sad, she doesn't want to do anything, do you/does one?"}, {"content": "", "heading": "Ví dụ: She thinks he will come, doesn't she? (Cô ấy nghĩ anh ấy sẽ đến, đúng không?)"}, {"content": "", "heading": "Câu đầu có It seems that + mệnh đề phụ, thì lấy mệnh đề phụ làm câu hỏi đuôi. Ví dụ: It seems that you are right, aren't you? (Hình như bạn đã đúng, phải vậy không?)"}, {"content": "", "heading": "13. Câu đầu có “must” Must có nhiều cách dùng cho nên tuỳ theo cách dùng mà sẽ có câu hỏi đuôi khác nhau"}, {"content": "", "heading": "a. “Must” chỉ sự cần thiết thì khi thành lập hỏi đuôi ta dùng “needn't”"}, {"content": "", "heading": "Ví dụ: They must study hard, needn't they? (Họ phải học hành chăm chỉ phải vậy không?)"}, {"content": "", "heading": "b. “Must” chỉ sự cấm đoán thì khi thành lập hỏi đuôi ta dùng “must”"}, {"content": "", "heading": "Ví dụ: You mustn't come late, must you? (Bạn không được đến muộn, nhớ chưa?)"}, {"content": "", "heading": "c. “Must” chỉ sự dự đoán ở hiện tại thì khi thành lập hỏi đuôi ta dựa vào động từ theo sau must"}, {"content": "", "heading": "Ví dụ: He must be a very intelligent student, isn't he? (Anh ta ắt hẳn là một học sinh rất thông minh, phải không?)"}, {"content": "", "heading": "d. “Must” chỉ sự dự đoán ở quá khứ (trong công thức must + have + Vp2) thì khi thành lập hỏi đuôi ta dùng have/has căn cứ theo chủ ngữ của câu."}, {"content": "She must have been tired after a long journey, hasn't she? (Cô ấy hẳn là đã rất mệt sau một chuyến đi dài phải không?)", "heading": "Ví dụ: You must have stolen my bike, haven't you? (Bạn chắc hẳn là đã lấy cắp xe của tôi, phải không?)"}, {"content": "", "heading": "14. Câu cảm thán, lấy danh từ trong câu đổi thành đại từ cùng với dùng is, am, are"}, {"content": "How intelligent the children are, aren't they? (Bọn trẻ thông minh quá phải không?)", "heading": "Ví dụ: What a beautiful dress, isn't it? (Cái váy ấy đẹp quá phải không?)"}, {"content": "Lấy mệnh đề phụ làm câu hỏi đuôi.", "heading": "15. Câu đầu có I + các động từ sau: think, believe, suppose, figure, assume, fancy, imagine, reckon, expect, seem, feel that + mệnh đề phụ"}, {"content": "", "heading": "Ví dụ: I think he will come here, won't he? (Tôi nghĩ là anh ấy sẽ đến phải vậy không?)"}, {"content": "", "heading": "Lưu ý:"}, {"content": "Cùng mẫu này nhưng nếu chủ từ không phải là “I” thì lại dùng mệnh đề chính làm câu hỏi đuôi.", "heading": "Mệnh đề chính có “not” thì vẫn tính như ở mệnh đề phụ. Ví dụ: I don't believe Mary can do it, can she? (Tôi tin Mary không làm chuyện đó, đúng không?)"}, {"content": "", "heading": "16. Câu có cấu trúc neither ... nor thì câu hỏi đuôi là sẽ chia ở số nhiều"}, {"content": "", "heading": "Ví dụ: Neither you nor I am children, are we? (Cả em và tôi đều không phải là trẻ con phải vậy không?)"}, {"content": "", "heading": "17. Ought to"}, {"content": "", "heading": "Câu có “ought to” thì ta sử dụng phần đuôi là “shouldn't”. Ví dụ: You ought to take a short rest, shouldn't you?"}, {"content": "“Need” vừa làm động từ thường, vừa làm động từ khuyết thiếu, nên:\\nNếu “need” là động từ thường thì khi thành lập hỏi đuôi ta phải mượn trợ động từ.", "heading": "18. Need"}, {"content": "Nếu “need” là động từ khuyết thiếu thì khi thành lập hỏi đuôi ta dùng luôn need.", "heading": "Ví dụ: She needs to water the flowers in the morning, doesn't she? (Cô ấy cần phải tưới hoa vào buổi sáng phải không?)"}, {"content": "", "heading": "Ví dụ: She needn't do it, need you? (cô ấy không cần nó, đúng không?)"}]}	ACTIVE	GRAMMAR	N - CÂU HỎI ĐUÔI - TAG QUESTION	\N
9a9cb0a7-4455-4138-ad67-cef4fbdf7fef	135214f4-611e-45a7-a4b8-076794ab24a0	N - THÌ ĐỘNG TỪ - VERB TENSES	5	{"title": "N - THÌ ĐỘNG TỪ - VERB TENSES", "sections": []}	ACTIVE	GRAMMAR	N - THÌ ĐỘNG TỪ - VERB TENSES	\N
7fdc1399-623f-4a48-9675-d031e871546d	135214f4-611e-45a7-a4b8-076794ab24a0	SO SÁNH - COMPARISON	6	{"title": "LÝ THUYẾT SO SÁNH", "sections": [{"content": "", "heading": "LÝ THUYẾT SO SÁNH – COMPARISION"}, {"content": "", "heading": "A. LÍ THUYẾT"}, {"content": "So sánh ngang bằng dùng để miêu tả hai đối tượng giống nhau hoặc bằng nhau về một hoặc nhiều thuộc tính nào đó.", "heading": "I. So sánh ngang bằng (Equality)"}, {"content": "", "heading": "1. Với tính từ và trạng từ"}, {"content": "Công thức: S + V + as + adj/adv + as + .....\\nVí dụ:\\n+ She is as tall as Huong. (Cô ấy cao bằng Hương.)\\n+ She learns as well as her sister does. (Cô ấy học tốt như chị gái mình.)", "heading": "a. Thể khẳng định"}, {"content": "Công thức: S + V + not + as/so + adj/adv + as +....\\nVí dụ:\\n+ This exercise is not as/so difficult as I think (it is). (Bài tập này không khó như tôi nghĩ.)\\n+ He doesn't study as/so hard as I do/me. (Anh ấy không học hành chăm chỉ bằng tôi.)", "heading": "b. Thể phủ định"}, {"content": "", "heading": "2. Với danh từ"}, {"content": "Công thức: S + V + as many/ few + N (số nhiều) + as + .....\\nVí dụ:\\n+ I have as many exercises as my brother does.\\n(Tôi có nhiều bài tập như anh trai tôi.)\\n+ We have as few problems to solve as yesterday.\\n(Hôm nay chúng tôi có vài vấn đề phải xử lí như ngày hôm qua.)", "heading": "a. Với danh từ số nhiều"}, {"content": "Công thức: S + V + as much/little + N (không đếm được) + as +....\\nVí dụ:\\n+ I don't have as much money as you do.\\n(Tôi không có nhiều tiền như bạn.)\\n+ My brother has as little time to play football as I do.\\n(Anh trai tôi có ít thời gian chơi bóng đá như tôi.)", "heading": "b. Với danh từ không đếm được"}, {"content": "So sánh hơn là so sánh đối tượng này hơn đối tượng kia về một hoặc nhiều thuộc tính nào đó.", "heading": "II. So sánh hơn (Comparative)"}, {"content": "", "heading": "1. Tính từ/trạng từ ngắn và tính từ/trạng từ dài"}, {"content": "+ có một âm tiết\\nVí dụ:\\nBig (to), small (nhỏ), hot (nóng), cold (lạnh), thin (gầy), fat (béo), ....\\n+ có hai âm tiết tận cùng là một trong năm đuôi sau:\\n- y: happy (hạnh phúc), easy (dễ dàng), early (sớm), heavy (nặng), lazy (lười biếng)...\\n- er: clever (thông minh, lanh lợi)\\n- le: single (độc thân), simple (đơn giản)\\n- ow: narrow (hẹp)\\n- et: quiet (yên tĩnh)\\nLưu ý: Những tính từ/ trạng từ hai âm tiết tận cùng là đuôi -y chỉ được coi là tính từ/ trạng từ ngắn khi bản thân nó có đuôi -y.\\nVí dụ:\\nlovely (đáng yêu) là tính từ dài vì nó được cấu tạo bởi love + ly → lovely.\\nquickly (nhanh) là trạng từ dài vì nó được cấu tạo bởi quick + ly → quickly.", "heading": "a. Tính từ/trạng từ ngắn là những tính từ/trạng từ:"}, {"content": "Ví dụ:\\nBeautiful (xinh đẹp), handsome (đẹp trai), intelligent (thông minh), hard-working (chăm chỉ)....", "heading": "b. Tính từ/ trạng từ dài là những tính từ/ trạng từ có từ hai âm tiết trở lên nhưng không phải một trong năm đuôi kể trên."}, {"content": "", "heading": "2. So sánh hơn với tính từ/ trạng từ ngắn và dài"}, {"content": "Công thức: S + V + adj/ adv + er + than + ...\\nVí dụ:\\n+ She looks happier than (she did) yesterday.\\n(Hôm nay cô ấy trông tươi tỉnh hơn hôm qua.)\\n+ He learns harder than his elder brother does.\\n(Anh ấy học hành chăm chỉ hơn anh trai của anh ấy.)\\nLưu ý:\\n+ Những tính từ hai âm tiết, kết thúc bằng chữ \\"y\\" thì bỏ \\"y\\" thêm \\"ier\\" trong so sánh hơn và \\"iest\\" trong so sánh hơn nhất.\\nVí dụ:\\nEasy → easier → easiest.\\n+ Những tính từ ngắn kết thúc bằng một phụ âm mà trước nó là một nguyên âm thì ta gấp đôi phụ âm rồi thêm \\"-er\\" trong so sánh hơn và \\"est\\" trong so sánh hơn nhất.\\nVí dụ:\\nBig → bigger → biggest.", "heading": "a. So sánh hơn với tính từ và trạng từ ngắn"}, {"content": "Công thức: S + V + more + adj/ adv + than + ...\\nVí dụ:\\n+ She is more beautiful than her sister.\\n(Cô ấy xinh hơn chị gái cô ấy.)\\n+ Huong dances more beautifully than other competitors.\\n(Hương nhảy đẹp hơn những người dự thi khác.)", "heading": "b. So sánh hơn với tính từ và trạng từ dài"}, {"content": "Công thức: S + V + more + N + than + ...\\nVí dụ:\\n+ She has more money than me. (Cô ấy có nhiều tiền hơn tôi.)", "heading": "3. So sánh hơn với danh từ"}, {"content": "So sánh nhất là khi chúng ta so sánh một cái gì đó là hơn tất cả những cái khác (ít nhất từ ba đối tượng so sánh trở lên), như là tốt nhất, đẹp nhất....", "heading": "III. So sánh nhất (Superlative)"}, {"content": "Công thức: S + V + the + adj/ adv + est + (N)+ ...\\nVí dụ:\\n+ He is the tallest (student) in my class.\\n(Anh ấy là người cao nhất trong lớp tôi.)\\n+ My mother gets up the earliest in my family.\\n(Mẹ tôi dậy sớm nhất nhà.)", "heading": "1. Với tính từ và trạng từ ngắn"}, {"content": "Công thức: S + V + the + most + adj/adv + (N) + ...\\nVí dụ:\\n+ My mother is the most beautiful (woman) in the world.\\n(Mẹ tôi là người đẹp nhất thế gian này.)\\n+ Mary sings the most beautifully in the group.\\n(Mary hát hay nhất nhóm.)", "heading": "2. Với tính từ và trạng từ dài"}, {"content": "Công thức: S + V + the + most + N + ...\\nVí dụ:\\n+ He is a billionaire. He has the most money.\\n(Anh ấy là tỉ phú. Anh ấy có nhiều tiền nhất.)", "heading": "3. Với danh từ"}, {"content": "Good/well (tốt/ giỏi)\\n+ So sáng hơn: better\\n+ So sánh nhất: the best\\nBad (tệ, tồi, dốt):\\n+ So sánh hơn: worse\\n+ So sánh nhất: the worst\\nMuch/many (nhiều):\\n+ So sánh hơn: more\\n+ So sánh nhất: the most\\nLittle (ít):\\n+ So sánh hơn: less\\n+ So sánh nhất: the least\\nFar (xa):\\n+ So sánh hơn: farther/further\\n+ So sánh nhất: the farthest/the furthest\\nOld (già, cũ):\\n+ So sánh hơn: older/elder\\n+ So sánh nhất: the oldest/eldest", "heading": "Lưu ý: Có một số tính từ và trạng từ không theo quy tắc trên"}, {"content": "", "heading": "IV. So sánh kép (Double comparative)"}, {"content": "", "heading": "1. So sánh luỹ tiến (càng ngày càng)"}, {"content": "", "heading": "a. Với tính từ ngắn"}, {"content": "Ví dụ:\\n+ The summer is coming. It gets hotter and hotter.\\n(Mùa hè đang đến. Trời càng ngày càng nóng.)", "heading": "Công thức: Adj + er + and + adj + er"}, {"content": "", "heading": "b. Với tính từ dài"}, {"content": "Ví dụ:\\n+ She is more and more attractive. (Cô ấy càng ngày càng hấp dẫn.)\\n+ The environment is less and less pure. (Môi trường ngày càng ít trong lành.)", "heading": "Công thức: more/less and more/less + adj"}, {"content": "", "heading": "c. Với danh từ"}, {"content": "Ví dụ:\\n+ There are more and more people moving to big cities to look for jobs.\\n(Ngày càng có nhiều người đến những thành phố lớn để kiếm việc làm.)", "heading": "Công thức: more and more + N"}, {"content": "Công thức:", "heading": "2. So sánh đồng tiến (càng... càng)"}, {"content": "Ví dụ:\\n+ The older he gets, the weaker he is. (Ông ấy càng già càng yếu.)\\n+ The more difficult the exercise is, the more interesting it is.\\n(Bài tập càng khó thì càng thú vị.)\\n+ The more I know him, the less I like him.\\n(Tôi càng biết nhiều về anh ấy thì tôi càng ít thích anh ấy.)\\nLưu ý:\\nTrong câu so sánh kép, nếu túc từ là một danh từ thì ta đặt danh từ ấy ngay sau tính từ so sánh.\\nVí dụ:\\n+ The more English vocabulary we know, the better we speak.\\nCàng biết nhiều từ vựng tiếng Anh, ta càng nói tốt hơn.\\nLưu ý: Một số tính từ/ trạng từ không dùng ở dạng so sánh vì bản thân chúng đã mang tính tuyệt đối:\\nComplete (hoàn toàn), favorite (yêu thích), ideal (lí tưởng), unique (duy nhất), excellent (xuất sắc), full (đầy), empty (rỗng), perfect (hoàn hảo), right (đúng), really (thật sự), extreme (cực độ, tột bậc), supreme (thượng hạng), absolute (tuyệt đối), ...", "heading": "the + (so sánh hơn) comparative adj / adv+ S +V,  the (so sánh hơn) comparative adj / adv + S + V"}, {"content": "", "heading": "V. Một số công thức khác"}, {"content": "Công thức:", "heading": "1. So sánh gấp nhiều lần (multiple numbers comparison)"}, {"content": "* Là những số như half/twice/3, 4, 5... times; Phân số; Phần trăm.\\nVí dụ:\\n+ She types twice as fast as I do.\\n(Cô ấy đánh máy nhanh gấp hai lần tôi đánh máy.)\\n+ In many countries in the world with the same job, women only get 40 - 50% as much salary as men.\\n(Ở nhiều quốc gia, phụ nữ chỉ nhận được lương bằng với 40 - 50% lương của người đàn ông khi họ có cùng một công việc.)\\n+ This encyclopedia costs twice as much as the other one.\\n(Bộ sách bách khoa toàn thư này mắc gấp đôi bộ còn lại.)\\nTừ image 1 (tiếp theo):\\n+ At the clambake last week, Fred ate three times as many oysters as Barney.\\n(Trong buổi tiệc tuần trước, Fred ăn hàu nhiều gấp 3 lần Barney.)\\nLưu ý:\\nKhi dùng so sánh loại này phải xác định rõ danh từ đó là đếm được hay không đếm được vì đằng trước chúng có much và many.", "heading": "S + V + multiple numbers * + as + much/many/adj/adv + (N) + as + N/pronoun"}, {"content": "", "heading": "2. Từ chỉ số lượng dùng trước tính từ so sánh hơn để nhấn mạnh"}, {"content": "Ví dụ:\\n+ She is much more hard-working than me. (Cô ấy chăm hơn tôi nhiều.)", "heading": "Công thức: S + V + much/ a lot/ far/ a little/ a bit... + so sánh hơn + than + ..."}, {"content": "", "heading": "3. Cấu trúc bắt đầu bằng \\"Of the two\\""}, {"content": "Ví dụ:\\n+ Of the two sisters, Mary is the prettier. (Trong số hai chị em gái, Mary xinh hơn.)", "heading": "Công thức: Of the two + N (số nhiều), S + V + the + so sánh hơn"}, {"content": "Ví dụ:\\n+ The population of China is much larger than that of any countries in the world.\\n(Dân số của Trung Quốc lớn hơn nhiều so với dân số của bất cứ quốc gia nào trên thế giới.)\\n+ The prices of Japanese cars are higher than those of Chinese ones.\\n(Giá ô tô Nhật cao hơn giá ô tô Trung Quốc.)", "heading": "4. Để tránh lặp lại danh từ trong so sánh hơn, kém, ngang bằng, người ta dùng \\"that\\" thay cho danh từ số ít và \\"those\\" thay cho danh từ số nhiều."}]}	ACTIVE	GRAMMAR	SO SÁNH - COMPARISON	\N
0ccbfe71-184a-4015-8ba2-b49b3721180a	40a22bef-8b76-400f-bed3-e5c8869ae71d	SỰ PHỐI HỢP THÌ - THE SEQUENCE OF TENSES	2	{"title": "LÝ THUYẾT SỰ PHỐI HỢP THÌ", "sections": [{"content": "Một câu có thể bao gồm một mệnh đề chính (main clause) và một hoặc nhiều mệnh đề phụ (subordinate clause). Khi trong câu có hai mệnh đề trở lên, các động từ phải có sự phối hợp về thì.", "heading": "SỰ PHỐI HỢP THÌ – THE SEQUENCE OF TENSES"}, {"content": "", "heading": "1. Các quy tắc"}, {"content": "", "heading": "1. WHEN"}, {"content": "", "heading": "a. Diễn tả hành động xảy ra nối tiếp nhau"}, {"content": "", "heading": "Trong quá khứ: WHEN + S + V (quá khứ đơn), S + V (quá khứ đơn)"}, {"content": "", "heading": "Ví dụ: When students heard the bell, they stood up and left. (Khi học sinh nghe thấy tiếng chuông, họ đứng dậy và ra về.)"}, {"content": "", "heading": "Trong tương lai: WHEN + S + V (hiện tại đơn), S + V (tương lai đơn)"}, {"content": "", "heading": "Ví dụ: When I see him, I will give him your regards. (Khi tôi gặp anh ấy, tôi sẽ chuyển cho anh ấy lời hỏi thăm của cậu.)"}, {"content": "", "heading": "b. Diễn tả hành động đang xảy ra thì có hành động khác xen vào"}, {"content": "", "heading": "Trong quá khứ: WHEN + S + V (quá khứ tiếp diễn), S + V (quá khứ đơn)"}, {"content": "", "heading": "Ví dụ: When she was having a bath, she saw a mouse. (Khi cô ấy đang tắm, cô ấy nhìn thấy một con chuột.)"}, {"content": "", "heading": "Trong tương lai: WHEN + S + V (hiện tại đơn), S + V (tương lai tiếp diễn) Tương lai tiếp diễn: S + WILL + BE + Ving"}, {"content": "", "heading": "2. BY + TIME"}, {"content": "", "heading": "a. by + trạng từ của quá khứ → động từ chia thì quá khứ hoàn thành"}, {"content": "", "heading": "Ví dụ: I had worked for the company for 30 years by the end of last month (Tôi đã làm việc cho công ty được 30 năm tính đến cuối tháng trước.)"}, {"content": "Tương lai hoàn thành: S + WILL + HAVE + VP2", "heading": "b. by + trạng từ của tương lai → động từ chia thì tương lai hoàn thành"}, {"content": "", "heading": "Ví dụ: I will have worked for the company for 30 years by the end of next month (Tôi sẽ làm việc cho công ty được 30 năm tính đến cuối tháng sau.)"}, {"content": "", "heading": "3. AT + GIỜ/ AT THIS TIME"}, {"content": "", "heading": "a. at + giờ; at this time + thời gian trong quá khứ → chia thì quá khứ tiếp diễn b. at + giờ; at this time + thời gian trong tương lai → chia thì tương lai tiếp diễn"}, {"content": "", "heading": "Ví dụ: At 3 p.m yesterday, we were learning English at school. At 3 p.m tomorrow, we will be learning English at school."}, {"content": "S + V (hiện tại hoàn thành) + since + S + V (quá khứ đơn)", "heading": "4. SINCE"}, {"content": "", "heading": "Ví dụ: I haven't seen my old friends since we left school. (Tôi đã không gặp lại những người bạn cũ kể từ khi chúng tôi ra trường.)"}, {"content": "", "heading": "5. UNTIL/ AS SOON AS"}, {"content": "", "heading": "a. S + V (tương lai đơn) + UNTIL; AS SOON AS + S + V (hiện tại đơn; hiện tại hoàn thành)"}, {"content": "", "heading": "Ví dụ: I will wait until you come back. (Tôi sẽ đợi cho đến khi em quay trở lại.) I will call you as soon as I have finished my work. (Anh sẽ gọi cho em ngay khi anh xong việc.)"}, {"content": "", "heading": "b. V (nguyên dạng)/ Don't + V (nguyên dạng) + UNTIL/ AS SOON AS + S + V (hiện tại đơn/ hiện tại hoàn thành)"}, {"content": "", "heading": "Ví dụ: Wait here until I come back. (Đợi ở đây cho đến khi mình quay lại nha!) Don't leave the room until I come back. (Đừng rời khỏi phòng cho đến khi mình quay lại nhé!)"}, {"content": "", "heading": "6. BY THE TIME"}, {"content": "", "heading": "a. BY THE TIME + S + V (quá khứ đơn), S + V (quá khứ hoàn thành)"}, {"content": "", "heading": "Ví dụ: By the time you went to the cinema, the film had already started. (Vào lúc bạn đến rạp chiếu phim, bộ phim đã bắt đầu.)"}, {"content": "", "heading": "a. BY THE TIME + S + V (hiện tại đơn), S + V (tương lai hoàn thành)"}, {"content": "", "heading": "Ví dụ: By the time you return, we will have bought a new house. (Vào lúc bạn quay trở về, chúng tôi sẽ đã mua được một ngôi nhà mới rồi.)"}, {"content": "", "heading": "7. WILL + V (nguyên dạng) - BE GOING TO + V (nguyên dạng)"}, {"content": "Diễn đạt một quyết định ngay tại thời điểm nói Ví dụ: George phoned while you were out. OK. I'll phone him back.\\nDiễn đạt lời dự đoán không có căn cứ Ví dụ: I think he will get the job.", "heading": "Thì tương lai đơn — WILL + V (bare):"}, {"content": "Diễn đạt một kế hoạch, dự định Ví dụ: I bought some paint. I am going to paint my house.\\nDiễn đạt một lời dự đoán dựa vào bằng chứng ở hiện tại Ví dụ: The sky is very cloudy. It is going to rain.", "heading": "Thì tương lai gần — BE GOING TO + V (bare):"}, {"content": "", "heading": "Ví dụ: When you come tomorrow, they will be playing tennis. (Khi bạn đến vào ngày mai, thì họ sẽ đang chơi tennis rồi.)"}, {"content": "", "heading": "c. Diễn tả hành động xảy ra xong rồi mới tới hành động khác"}, {"content": "", "heading": "Trong quá khứ: WHEN + S + V (quá khứ đơn), S + V (quá khứ hoàn thành)"}, {"content": "", "heading": "Ví dụ: Last night, when we arrived at the theater, they had sold out all the tickets. (Tối hôm qua, khi chúng tôi đến nhà hát, họ đã bán hết vé rồi.)"}, {"content": "", "heading": "Trong tương lai: WHEN + S + V (hiện tại đơn), S + V (tương lai hoàn thành)"}, {"content": "", "heading": "Ví dụ: When you come back, I will have typed this email. (Khi bạn quay lại, tôi sẽ đánh máy xong bức thư điện tử này.)"}, {"content": "THIS; IT IS THE FIRST; SECOND; THIRD.... TIME + S + V (hiện tại hoàn thành) THIS; IT IS THE LAST TIME + S + V (quá khứ đơn)\\nVí dụ: This is the first time I have ever met such a handsome boy. (Đây là lần đầu tiên tôi gặp một anh chàng đẹp trai đến thế) This is the last time I talked with you about that matter. (Đây là lần cuối cùng tôi nói với bạn về vấn đề này.)", "heading": "8. THE FIRST; LAST TIME"}, {"content": "S + V (hiện tại đơn) + THE + ADJ (est)/ MOST + ADJ + CLAUSE (hiện tại hoàn thành) S + V (quá khứ đơn) + THE + ADJ (est)/ MOST + ADJ + CLAUSE (quá khứ hoàn thành)\\nVí dụ: This is the most embarrassing experience I have ever had. This was the most embarrassing experience I had ever had. (Đây là trải nghiệm bối rối nhất mà tôi từng có.)", "heading": "9. TRONG CÂU SO SÁNH HƠN NHẤT"}]}	ACTIVE	GRAMMAR	SỰ PHỐI HỢP THÌ - THE SEQUENCE OF TENSES	\N
d9315cf5-428d-4d82-a65e-d3b8e98ac6e4	a8efe662-9202-4e83-822d-808656858e3e	THÀNH NGỮ - IDIOMS	5	{"title": "LÝ THUYẾT THÀNH NGỮ", "sections": [{"content": "", "heading": "A. MỘT SỐ THÀNH NGỮ THÔNG DỤNG"}, {"content": "The black sheep - nghịch tử, phá gia chi tử\\nBlue in the face - mãi mãi, lâu đến vô vọng\\nRed-letter day - ngày đáng nhớ vì có chuyện tốt lành, ngày vui\\nWhite as a ghost/sheet - trắng bệch, nhợt nhạt\\nWith flying colors - xuất sắc\\nOnce in a blue moon - năm thì mười hoạ, hiếm khi\\nBlack and white - rõ ràng\\nCatch sb red-handed - bắt tại trận\\nHave a yellow streak - có tính nhát gan\\nGet/give the green light - bật đèn xanh\\nOut of the blue - hoàn toàn bất ngờ\\nPaint the town red - ăn mừng\\nRed tape - nạn quan liêu\\nIn the pink = in good health - sức khoẻ tốt\\nLend color to st - chứng minh cái gì", "heading": "I. Thành ngữ có chứa màu sắc (Color)"}, {"content": "Break a leg - Good luck! (thường dùng để chúc may mắn)\\nScratch someone's back = Help someone out with the assumption that they will return the favor in the future - giúp đỡ người khác với hi vọng họ sẽ giúp lại mình\\nHit the nail on the head = Do or say something exactly right - nói chính xác, làm chính xác\\nSplitting headache = A severe headache - đau đầu như búa bổ\\nMake someone's blood boil - làm ai sôi máu, giận dữ\\nPay through the nose = To pay too much for something - trả giá quá đắt\\nBy the skin of one's teeth - sát sao, rất sát\\nPull someone's leg - chọc ai\\nFight tooth and claw/nail - đánh nhau dữ dội, cấu xé nhau\\nNot bat an eye = To not show any shock or surprise - không tỏ ra ngạc nhiên hay sốc\\nCost an arm and a leg - rất là đắt đỏ\\nGo to one's head - khiến ai kiêu ngạo\\nGet/have cold feet - mất hết can đảm, chùn bước\\nLed somebody by the nose = To control someone and make them do exactly what you want them to do - nắm đầu, dắt mũi ai\\nOff one's head - điên, loạn trí\\nPut one's foot in it - gây nhầm lẫn, bối rối, phạm một sai lầm gây bối rối\\nStay/keep/be on one's toe - cảnh giác, thận trọng\\nHave in mind - đang suy tính, cân nhắc\\nAt heart - thực chất, cơ bản (basically, fundamentally)\\nFace the music - chịu trận\\nLike the back of one's hand - rõ như lòng bàn tay\\nThe twinkling of an eye - trong nháy mắt\\nOn the tip of tongue - dùng khi muốn diễn tả ai đó không thể nhớ ra được điều gì mặc dù đã chắc chắn biết về nó\\nPut one's foot in one's mouth - nói một điều ngu ngốc làm xúc phạm đến người khác\\nStick one's nose into one's business - chúi mũi vào việc của người khác\\nFeel st in one's bones - cảm nhận rõ rệt\\nA real pain in the neck - sốc, nghiêm trọng\\nFace to face - trực tiếp\\nSee eye to eye with sb = totally agree - đồng tình\\nKeep one's head above the water - xoay xở\\nHave egg on one's face - xấu hổ\\nWord of mouth - đồn đại, truyền miệng\\nHeart to heart - chân thành\\nBody and soul - hết lòng, hết dạ\\nFlesh and blood - người có máu mủ ruột thịt\\nSkin and bones - tiều tụy thảm thương, chỉ còn da bọc xương\\nLend an ear to sb/st - lắng nghe một cách chân thành\\nTrip over one's big feet - tự vấp ngã\\nIn one's capable hands - trong quyền giải quyết\\nUp to your eyes - rất bận\\nHave a head for st - giỏi về cái gì\\nA sweet tooth - người thích ăn đồ ăn ngọt\\nHave st at one's fingertips = To have the information, knowledge, etc. That is needed in a particular situation and be able to find it easily and use it quickly - nhận được thông tin/ kiến thức cần thiết một cách dễ dàng và nhanh chóng", "heading": "II. Thành ngữ có chứa các danh từ bộ phận (Body)"}, {"content": "Take the mickey out of sb = make fun of sb - chế nhạo, châm chọc ai\\nGet butterflies in one's stomach - cảm thấy bồn chồn\\nHave a bee in one's bonnet about st - ám ảnh về điều gì\\nWhen pigs fly = something will never happen - điều vô tưởng, không thể xảy ra\\nTeacher's pets - học sinh cưng\\nLet the cat out of the bag - tiết lộ bí mật\\nHuddle into a pen - lại gần nhau, túm tụm lại\\nKill two birds with one stone - một mũi tên trúng hai đích\\nA big fish in a small pond - thằng chột làm vua xứ mù\\nRain cats and dogs - mưa rất to\\nLike a fish out of water - như cá ra khỏi nước (bơ vơ, xa lạ, ngớ ngẩn)\\nLike water off a duck's back - nước đổ đầu vịt\\nDon't count yours the chicken before they hatch - đừng vội làm gì khi chưa chắc chắn\\nCatch the worms - nắm bắt cơ hội\\nBe in the doghouse - nếu bạn đang \\"in the doghouse\\", tức là ai đó đang khó chịu với bạn vì điều bạn đã làm\\nDon't look a gift horse in the mouth - đừng đòi hỏi về giá trị khi nhận được một món quà\\nCock- and -bull - bịa đặt, vẽ vời ra\\nChange horse in midstream - thay ngựa giữa dòng (ý nói thay đổi giữa chừng)", "heading": "III. Thành ngữ có chứa các con động vật (Animal)"}, {"content": "To be in deep water - rơi vào tình huống khó khăn\\nTo be in hot water - gặp rắc rối\\nBetter safe than sorry - cẩn tắc vô áy náy\\nMoney is the good servant but a bad master - khôn lấy của che thân, dại lấy thân che của\\nThe grass are always green on the other side of the fence - đứng núi này trông núi nọ\\nOne bitten, twice shy - chim phải đạn sợ cành cong\\nIn Rome do as the Romans do - nhập gia tuỳ tục\\nHonesty is the best policy - thật thà là thượng sách\\nA woman gives and forgives, a man gets and forgets - đàn bà cho và tha thứ, đàn ông nhận và quên\\nNo roses without a thorn - hồng nào mà chẳng có gai, việc nào mà chẳng có vài khó khăn!\\nSave for the rainy day - làm khi lành để dành khi đau\\nIt's an ill bird that fouls its own nest - vạch áo cho người xem lưng / Tốt đẹp phô ra xấu xa đậy lại\\nDon't trouble trouble till trouble troubles you - sinh sự sự sinh\\nStill water run deep - tằm ngấm tằm ngấm mà đấm chết voi\\nMen make house, women make home - đàn ông xây nhà, đàn bà xây tổ ấm\\nPenny wise pound foolish - tham bát bỏ mâm\\nMake the mare go - có tiền mua tiên cũng được\\nLike father, like son - con nhà tông không giống lông thì cũng giống cánh\\nThe die is cast - bút sa gà chết\\nTwo can play that game - ăn miếng trả miếng\\nPractice makes perfect - có công mài sắt có ngày nên kim\\nIgnorance is bliss - không biết thì dựa cột mà nghe\\nNo pain, no gain - có làm thì mới có ăn\\nA bad beginning makes a bad ending - đầu xuôi đuôi lọt\\nA clean fast is better than a dirty breakfast - giấy rách phải giữ lấy lề\\nBeauty is but skin-deep - cái nết đánh chết cái đẹp\\nCalamity is man's true touchstone - lửa thử vàng, gian nan thử sức.\\nDiamond cut diamond - vỏ quýt dày có móng tay nhọn\\nDiligence is the mother of success - có công mài sắt có ngày nên kim\\nDon't put off until tomorrow what you can do today - việc hôm nay chớ để ngày mai\\nA hot potato = something that is difficult or dangerous to deal with - vấn đề nan giải\\nA lost cause - hết hi vọng, không thay đổi được gì\\nIt never rains but it pours = good or bad things do not just happen a few at a time, but in large numbers all at once - hoạ vô đơn chí", "heading": "IV. Thành ngữ về cuộc sống (Life)"}, {"content": "A blind date - cuộc hẹn giữa hai người chưa hề quen biết\\nGolden handshake - món tiền hậu hĩnh dành cho người sắp nghỉ việc\\nOne's cup of tea - thứ mà ai đó thích\\nOdds and ends - linh tinh, vụn vặt\\nLeaps and bounds - nhảy vọt, vượt trội\\nBetween two stools = on the horns of a dilemma = when someone finds it difficult to choose between two alternatives - tiến thoái lưỡng nan\\nOn the house - không phải trả tiền\\nOff the peg - hàng may sẵn\\nOff the record - không chính thức, không được công bố\\nPart and parcel - thiết yếu, quan trọng\\nA shadow of a doubt - sự nghi ngờ\\nBeyond the shadow of a doubt - không hề nghi ngờ\\nThe last straw = a nail in one's coffin - giọt nước tràn ly\\nThe apple of one's eye - bảo bối của ai\\nGood egg - người có nhân cách, đáng tin cậy\\nClose shave = narrow escape - thoát chết trong gang tấc\\nWet blanket - người phá đám\\nA kick in the pants - một bài học để ứng xử tốt hơn\\nAn open-and-shut case - vấn đề dễ giải quyết\\nA shot in the dark - một câu đố\\nA big cheese - nhân vật tai to mặt lớn, người có vai vế, quyền lực\\nUps and downs - lúc thăng lúc trầm\\nIns and outs - những đặc tính và sự phức tạp\\nThe tip of the iceberg - phần nhìn thấy\\nCompulsive liar - kẻ nói dối chuyên nghiệp", "heading": "V. Thành ngữ là các cụm danh từ khác (Noun)"}, {"content": "To pour cold water on something - dội nước lạnh vào...\\nTo blow something out of the water - đánh bại, vượt\\nTo sell/go like hot cakes - đắt đỏ, đắt như tôm tươi\\nTo get in hot water = be in trouble/ have difficulty - gặp khó khăn\\nTo hit the books = to study - học\\nTo hit the roof = to hit the ceiling = to suddenly become angry - giận dữ\\nTo hit it off - tâm đầu ý hợp\\nTo make good time - di chuyển nhanh, đi nhanh\\nTo chip in - góp tiền\\nTo run an errand - làm việc vặt\\nTo fly off the handle - dễ nổi giận, phát cáu\\nTo cut it fine - đến sát giờ\\nTo jump the traffic lights - vượt đèn đỏ\\nTo put on an act - giả bộ, làm bộ\\nTo come to light - được biết đến, được phát hiện, được đưa ra ánh sáng.\\nTo pull one's weight - nỗ lực, làm tròn trách nhiệm\\nTo make ends meet - xoay xở để kiếm sống\\nTo get the hold of the wrong end of the stick - hiểu nhầm ai đó\\nTo cut and dried - cuối cùng, không thể thay đổi, rõ ràng, dễ hiểu\\nTo know by sight - nhận ra\\nTo take pains - làm việc cẩn thận và tận tâm\\nTo drop sb a line/note - viết thư cho ai\\nTo turn over a new leaf - bắt đầu thay đổi hành vi của mình\\nTo weigh up the pros and cons - cân nhắc điều hay lẽ thiệt\\nTo burn the midnight oil = to stay up working, especially studying late at night - thức khuya làm việc, học bài\\nTo put sb/st at one's disposal - cho ai tuỳ ý sử dụng\\nTo bring down the house - làm cho cả khán phòng vỗ tay nhiệt liệt\\nTo beat about the bush - vòng vo tam quốc\\nTo find fault with - chỉ trích, kiếm chuyện, bắt lỗi\\nTo take it amiss = to understand as wrong or insulting, or misunderstand - hiểu lầm\\nTo break the news - thông báo\\nTo drop a brick - lỡ lời, lỡ miệng\\nTo take st for granted - coi là hiển nhiên\\nTo break the ice - Thành ngữ này thường dùng để diễn tả làm một việc gì đó để giúp mọi người thư giãn và thoải mái, đặc biệt khi mới gặp\\nTo blow one's own trumpet - khoe khoang, khoác lác\\nTo miss the boat - lỡ mất cơ hội\\nTo put one's card on the table - thẳng thắn\\nTo call it a day = stop working - nghỉ, giải lao\\nTo hear a pin drop - im lặng, tĩnh lặng\\nTo blow hot and cold - hay thay đổi ý kiến, dao động\\nTo call the shots - chỉ huy, quyết định về những việc cần làm\\nTo draws the line - đặt giới hạn cho việc gì; phân biệt giữa hai thứ tương tự nhau\\nTo foot the bill - thanh toán tiền\\nTo carry the can - chịu trách nhiệm, chịu sự chỉ trích\\nTo throw the baby out with the bathwater - vứt bỏ những thứ đáng giá cùng lúc với rũ bỏ với thứ gì không còn cần\\nTo go with the flow - làm theo mọi người\\nTo keep his shirt on - bình tĩnh\\nTo let off steam - xả hơi", "heading": "VI. Thành ngữ là các cụm động từ khác (Verb)"}, {"content": "At the drop of a hat = immediately, instantly - ngay lập tức\\nOff and on/ on and off - không đều đặn, thỉnh thoảng\\nHigh and low = here and there = everywhere = far and wide - đó đây, khắp mọi nơi\\nSpick and span - ngăn nắp, gọn gàng\\nOn the spot = immediately - ngay lập tức\\nAt the eleventh hour - vào phút chót\\nOn the top of the world = walking on the air = over the moon = like a dog with two tails = happy - vui sướng, hạnh phúc\\nIn vain - vô ích\\nA piece of cake - dễ như ăn cháo\\nDown the drain - công cốc, đổ ra sông ra biển\\nUnder the weather = off color - không được khoẻ\\nThe end of the world - đáng để bận tâm\\nAs fit as a fiddle - khoẻ như vâm\\nOn probation - trong thời gian quản chế, tập sự (công việc)\\nHome and dry = with flying colors - thành công\\nApples and oranges = chalk and cheese - rất khác nhau, khác một trời một vực\\nAs long as your arm - rất dài\\nAs high as a kite - quá phấn khích, thường là do bị ảnh hưởng bởi đồ uống có cồn hoặc ma tuý\\nIn the same boat - ở trong cùng một hoàn cảnh\\nHot under the collar - điên tiết, cáu tiết\\nAs red as a beetroot - đỏ như củ cải đường/ngượng\\nFor good = permanently = forever - mãi mãi\\nNow and then = once in a while = sometimes = every so often = occasionally - thỉnh thoảng\\nFull of beans - hăng hái, sôi nổi, đầy năng lượng\\nAt a loose end = free - rảnh rỗi\\nA tall story = unbelievable - khó tin\\nAs cool as cucumber - bình tĩnh, không nao núng\\nPeace and quiet - bình yên và tĩnh lặng\\nBehind closed doors - kín, không công khai\\nHigh and dry = in a difficult situation, without help or money - trong tình huống khó khăn\\nPrim and proper = always behaving in a careful and formal way, and easily shocked by anything that is rude - kĩ lưỡng (quá mức), có chút bảo thủ\\nRough and ready = simple and prepared quickly but good enough for a particular situation - đơn giản, nhanh chóng nhưng vẫn đảm bảo chất lượng\\nSick and tired - vô cùng mệt mỏi\\nSafe and sound - bình an vô sự\\nWhite-collar - công chức, lao động bằng trí óc\\nBlue-collar - lao động tay chân\\nNowhere near - còn lâu, chắc là không\\nOut of sorts - ốm, yếu, buồn chán\\nOn the mend - hồi phục\\nOver the worst - vượt qua điều tồi tệ nhất\\nOn pins and needles = nervous - lo lắng", "heading": "VII. Thành ngữ là cụm tính từ/ trạng từ (Adj/Adv)"}]}	ACTIVE	GRAMMAR	THÀNH NGỮ - IDIOMS	\N
9d5f14ed-564b-406a-b2c9-6e3fbea1df22	40a22bef-8b76-400f-bed3-e5c8869ae71d	TRẬT TỰ CỦA TÍNH TỪ - THE ORDERS OF THE ADJECTIVES	3	{"title": "TRẬT TỰ CỦA TÍNH TỪ - THE ORDERS OF THE ADJECTIVES", "sections": []}	ACTIVE	GRAMMAR	TRẬT TỰ CỦA TÍNH TỪ - THE ORDERS OF THE ADJECTIVES	\N
1962ad1d-f51d-4a60-94f3-29bdd6c5f842	a8efe662-9202-4e83-822d-808656858e3e	TRỌNG ÂM - STRESS	6	{"title": "LÝ THUYẾT TRỌNG ÂM", "sections": [{"content": "Tiếng Anh là ngôn ngữ đa âm tiết. Những từ có hai âm tiết trở lên luôn có một âm tiết phát âm khác biệt hẳn so với những âm tiết còn lại về độ dài, độ lớn và độ cao. Âm tiết nào được phát âm to hơn, giọng cao hơn và kéo dài hơn các âm khác trong cùng một từ thì ta nói âm tiết đó được nhấn trọng âm. Hay nói cách khác, trọng âm rơi vào âm tiết đó. Khi nhìn vào phiên âm của một từ thì trọng âm của từ đó được kí hiệu bằng dấu (') ở phía trước, bên trên âm tiết đó.\\nVí dụ: happy /'hæpi/: trọng âm rơi vào âm tiết thứ nhất. clever /'klevər/: trọng âm rơi vào âm tiết thứ nhất. arrange /ə'reɪndʒ/: trọng âm rơi vào âm tiết thứ hai. engineer /ɛndʒɪ'nɪə/: trọng âm rơi vào âm tiết thứ ba.", "heading": "I. Định nghĩa về trọng âm"}, {"content": "Trọng âm từ đóng vai trò quan trọng trong việc phân biệt được từ này với từ khác khi chúng ta nghe và nói tiếng Anh. Người bản ngữ phát âm bất cứ từ nào đều có trọng âm. Vì vậy, đặt trọng âm sai âm tiết hay không sử dụng trọng âm sẽ khiến người bản xứ khó có thể hiểu được là người học tiếng Anh muốn nói gì và họ cũng gặp không ít khó khăn trong việc nghe hiểu người bản xứ. Chẳng hạn: Từ desert có hai cách nhấn trọng âm: trọng âm rơi vào âm tiết thứ nhất /'dezərt/ thì đó là danh từ, có nghĩa là sa mạc, nhưng trọng âm rơi vào âm tiết thứ hai /dɪ'zɜrt/ thì đó là động từ, có nghĩa là bỏ rơi, đào ngũ. Trong tiếng Anh, có một số từ được viết giống nhau nhưng trọng âm ở vị trí khác nhau tuỳ theo từ loại. Như vậy phát âm đúng trọng âm của một từ là yếu tố đầu tiên giúp chúng ta có thể nghe hiểu và nói được như người bản ngữ.", "heading": "II. Ý nghĩa của trọng âm"}, {"content": "Để hiểu được trọng âm của một từ, trước hết chúng ta phải hiểu được thế nào là âm tiết. Mỗi từ đều được cấu tạo từ các âm tiết.\\nÂm tiết là một đơn vị phát âm, gồm có một âm nguyên âm (/ʌ/, /æ/, /ɑː/, /ɔɪ/, /ʊə/...) và các phụ âm (p, k, t, m, n...) bao quanh hoặc không có phụ âm bao quanh. Từ có thể có một, hai, ba hoặc nhiều hơn ba âm tiết.\\nVí dụ: beautiful /'bjuːtɪful/: có ba âm tiết. quickly /'kwɪkli/: có hai âm tiết.", "heading": "III. Âm tiết tiếng Anh"}, {"content": "", "heading": "IV. Các quy tắc đánh trọng âm"}, {"content": "", "heading": "1. Trọng âm theo phiên âm a. Quy tắc"}, {"content": "Ví dụ: mother /'mʌðə/: trọng âm rơi vào âm tiết thứ nhất vì âm thứ hai có chứa âm /ə/. hotel /həʊ'tel/: trọng âm rơi vào âm tiết thứ hai vì âm thứ nhất có chứa âm /əʊ/.\\nLưu ý: Nếu như trong một từ có chứa cả hai loại âm là /ə/ và /əʊ/ thì trọng âm rơi vào phần có chứa âm /əʊ/.\\nVí dụ: suppose /sə'pəʊz/: trọng âm rơi vào âm thứ hai. ago /ə'gəʊ/: trọng âm rơi vào âm thứ hai. opponent /ə'pəʊnənt/: trọng âm rơi vào âm thứ hai.", "heading": "- Trọng âm không bao giờ rơi vào âm /ə/ hoặc là âm /əʊ/."}, {"content": "Ví dụ: disease/dɪ'ziːz/: trọng âm rơi vào âm tiết thứ hai vì âm thứ hai có chứa nguyên âm dài /iː/. explain /ɪk'spleɪn/: trọng âm rơi vào âm tiết thứ hai vì âm thứ hai có chứa nguyên âm đôi /eɪ/. comprehend /kɒmprɪ'hend/: trọng âm rơi vào âm tiết thứ ba vì âm tiết thứ ba kết thúc với hai phụ âm /nd/.", "heading": "- Trọng âm thường rơi vào nguyên âm dài/nguyên âm đôi hoặc âm cuối kết thúc với nhiều hơn một phụ âm."}, {"content": "Ví dụ: happy /'hæpi/: trọng âm rơi vào âm tiết đầu, vì cả /æ/ và /i/ đều là nguyên âm ngắn. animal /'ænɪməl/: trọng âm rơi vào âm tiết đầu vì cả /æ/, /ɪ/, /ə/ đều là nguyên âm ngắn.", "heading": "- Nếu tất cả các âm mà ngắn hết thì trọng âm rơi vào âm tiết thứ nhất."}, {"content": "Hậu tố là thành phần được thêm vào sau từ gốc. Hậu tố không phải là một từ và cũng không có nghĩa khi nó đứng riêng biệt.", "heading": "2. Trọng âm với hậu tố/đuôi"}, {"content": "-eer: Ví dụ: volunteer/ˌvɒlən'tɪə/, career/kə'rɪə/\\n-ee: Ví dụ: employee/ɛmplɔː'iː/, interviewee /ɪntəvjuː'iː/\\n-oo: Ví dụ: bamboo/bam'buː/, taboo/tə'buː/\\n-oon: Ví dụ: afternoon/ɑːftə'nuːn/, cartoon/kɑː'tuːn/\\n-ese: Ví dụ: vietnamese /ˌvɪətnə'miːz/\\n-ette: Ví dụ: cigarette /sɪgə'ret/\\n-esque: Ví dụ: picturesque /ˌpɪktʃə'resk/\\n-ade: Ví dụ: lemonade /ˌlemə'neɪd/\\n-mental: Ví dụ: environmental /ɛnvʌɪrən'ment(ə)l/\\n-nental: Ví dụ: continental /kɒntrɪ'nent(ə)l/\\n-ain: Ví dụ: entertain /ɛntə'teɪn/", "heading": "a. Hậu tố/đuôi nhận trọng âm"}, {"content": "-ion: Ví dụ: population /pɒpjʊ'leɪʃ(ə)n/\\n-ic: Ví dụ: economic /ˌiːkə'nɒmɪk/\\n-ial: Ví dụ: industrial /ɪn'dʌstrɪəl/\\n-ive: Ví dụ: expensive /ɪk'spensɪv/\\n-ible: Ví dụ: responsible /rɪ'spɒnsɪb(ə)l/\\n-ity: Ví dụ: ability /ə'bɪləti/\\n-graphy: Ví dụ: photography /fə'tɒgrəfi/\\n-ious/eous: Ví dụ: industrious /ɪn'dʌstrɪəs/, advantageous /ədvən'teɪdʒəs/\\n-ish: Ví dụ: selfish /'selfɪʃ/\\n-ian: Ví dụ: politician /pɒlɪ'tɪʃ(ə)n/", "heading": "b. Hậu tố/đuôi làm trọng âm rơi vào trước âm đó"}, {"content": "-y: Ví dụ: biology /bʌɪ'ɒlədʒi/, accompany /ə'kʌmpəni/\\n-ce: Ví dụ: difference /'dɪf(ə)r(ə)ns/\\n-ate: Ví dụ: graduate /'grædjʊeɪt/, concentrate /'kɒns(ə)ntreɪt/\\n-ise/-ize: Ví dụ: apologise /ə'pɒlədʒʌɪz/\\nism/izm: Ví dụ: tourism/'tʊərɪz(ə)m/, criticism/'krɪtɪsɪz(ə)m/", "heading": "c. Hậu tố/đuôi làm trọng âm dịch chuyển ba âm tính từ cuối lên"}, {"content": "Trừ những hậu tố đã được liệt kê ở các mục a, b, c của phần 2 thì tất cả những hậu tố còn lại đều không ảnh hưởng đến trọng âm của từ.\\nVí dụ:\\n-ful: careful /'keəfl/(đuôi -ful không ảnh hưởng nên từ careful trọng âm rơi vào âm tiết thứ nhất và trọng âm rơi vào nguyên âm đôi eə.)\\n-er: danger /'dem(d)ʒə/(đuôi -er không ảnh hưởng nên từ danger trọng âm rơi vào âm tiết thứ nhất.)\\n-or: actor /'æktə/ (đuôi -or không ảnh hưởng nên từ actor trọng âm rơi vào âm tiết thứ nhất.)\\n-ist: scientist /'saɪəntɪst/ (đuôi -ist không ảnh hưởng đến trọng âm của từ và theo quy tắc trọng âm rơi vào nguyên âm đôi /aɪ/. Do đó, từ scientist trọng âm rơi vào âm tiết thứ nhất.)\\n-ous: dangerous /'deɪm(d)ʒ(ə)rəs/(đuôi -ous và đuôi -er không ảnh hưởng đến trọng âm của từ nên từ dangerous trọng âm rơi vào âm tiết thứ nhất.)\\n-ly: quickly/'kwɪkli/(đuôi -ly không ảnh hưởng đến trọng âm của từ. Do đó, từ quickly trọng âm rơi vào âm tiết đầu.)\\n-hood: childhood /'tʃʌɪldhʊd/(đuôi -hood không ảnh hưởng đến trọng âm của từ. Do đó, từ childhood có trọng âm rơi vào âm tiết đầu.)\\n-ship: membership /'membəʃɪp/(đuôi -ship và đuôi -er không ảnh hưởng đến trọng âm của từ nên từ membership trọng âm rơi vào âm tiết thứ nhất.)\\n-ment: entertainment/ɛntə'teɪnm(ə)nt/(đuôi -ment không ảnh hưởng đến trọng âm của từ, nên ta xét đến đuôi -ain. Theo quy tắc, đuôi -ain nhận trọng âm nên từ entertainment trọng âm rơi vào âm tiết thứ ba.)\\n-al: historical/hɪ'stɒrɪk(ə)l/(đuôi -al không ảnh hưởng nên ta bỏ qua đuôi -al và xét đến đuôi -ic. Theo quy tắc, đuôi -ic làm trọng âm rơi vào trước âm đó. Do đó, từ historical trọng âm rơi vào âm tiết thứ hai.)\\n-less: homeless /'həʊmlɪs/ (đuôi -less không ảnh hưởng đến trọng âm của từ. Do đó, từ homeless trọng âm rơi vào âm tiết thứ nhất.)\\n-ness: friendliness /'fren(d)lɪnəs/ (đuôi -ness và đuôi -ly không ảnh hưởng đến trọng âm của từ. Do đó, từ friendliness có trọng âm rơi vào âm tiết thứ nhất.)\\n-age: shortage /'ʃɔːtɪdʒ/ (đuôi -age không ảnh hưởng đến trọng âm của từ. Do đó, từ shortage có trọng âm rơi vào âm tiết thứ nhất.)\\n-ure: pleasure /'pleʒə/ (đuôi -ure không ảnh hưởng đến trọng âm của từ. Do đó, từ pleasure có trọng âm rơi vào âm tiết thứ nhất.)\\n-ledge: knowledge /'nɒlɪdʒ/ (đuôi -ledge không ảnh hưởng đến trọng âm của từ. Do đó, từ knowledge có trọng âm rơi vào âm tiết thứ nhất.)\\n-ing: teaching /'tiːtʃɪŋ/ (đuôi -ing không ảnh hưởng đến trọng âm của từ trường hợp này có i:. Do đó, từ teaching có trọng âm rơi vào âm tiết thứ nhất.)\\n-ed: listened /'lɪs(ə)nd/ (đuôi -ed không ảnh hưởng đến trọng âm của từ. Do đó, listened có trọng âm rơi vào âm tiết thứ nhất, vì theo quy tắc trọng âm không rơi vào âm /ə/.)\\n-able: comfortable /'kʌmf(ə)təb(ə)l/ (đuôi -able không ảnh hưởng đến trọng âm của từ. Do đó, từ comfortable có trọng âm rơi vào âm tiết thứ nhất, vì theo quy tắc trọng âm không rơi vào âm /ə/.)\\n-dom: freedom /'friːdəm/ (đuôi -dom không ảnh hưởng đến trọng âm của từ. Do đó, từ freedom có trọng âm rơi vào âm tiết thứ nhất.)\\n-some: troublesome /'trʌb(ə)ls(ə)m/ (đuôi -some không ảnh hưởng đến trọng âm của từ. Do đó, từ troublesome có trọng âm rơi vào âm tiết thứ nhất.)\\n-ent/-ant dependent /dɪ'pend(ə)nt/ ( đuôi -ent không ảnh hưởng đến trọng âm của từ. Do đó, từ dependent trọng âm rơi vào âm tiết thứ hai theo quy tắc trọng âm rơi vào những âm kết thúc với nhiều hơn một phụ âm.)\\nassistant /ə'sɪst(ə)nt/ (đuôi -ant không ảnh hưởng đến trọng âm của từ. Do đó, từ assistant trọng âm rơi vào âm tiết thứ hai theo quy tắc trọng âm không rơi vào âm /ə/.)", "heading": "d. Hậu tố không ảnh hưởng đến trọng âm của từ"}, {"content": "", "heading": "Danh sách từ vựng thay đổi trọng âm"}, {"content": "", "heading": "1. Conflict"}, {"content": "", "heading": "conflict /ˈkɒn.flɪkt/ (n): sự mâu thuẫn, tranh cãi"}, {"content": "", "heading": "conflict /kənˈflɪkt/ (v): mâu thuẫn, tranh cãi"}, {"content": "", "heading": "2. Contest"}, {"content": "", "heading": "contest /ˈkɒn.test/ (n): cuộc thi"}, {"content": "", "heading": "contest /kənˈtest/ (v): tranh cãi, đấu tranh"}, {"content": "", "heading": "3. Contrast"}, {"content": "", "heading": "contrast /ˈkɒntrɑːst/ (n): sự mâu thuẫn"}, {"content": "", "heading": "contrast /kənˈtrɑːst/ (v): mâu thuẫn, làm rõ sự tương phản"}, {"content": "", "heading": "4. Convert"}, {"content": "", "heading": "convert /ˈkɒn.vɜːt/ (n): người cải đạo"}, {"content": "", "heading": "convert /kənˈvɜːt/ (v): chuyển đổi, cải đạo"}, {"content": "", "heading": "5. Decrease"}, {"content": "", "heading": "decrease /ˈdiː.kriːs/ (n): sự giảm xuống"}, {"content": "", "heading": "decrease /dɪˈkriːs/ (v): giảm, suy giảm"}, {"content": "", "heading": "6. Import"}, {"content": "", "heading": "import /ˈɪm.pɔːt/ (n): hàng nhập khẩu"}, {"content": "", "heading": "import /ɪmˈpɔːt/ (v): nhập khẩu"}, {"content": "", "heading": "7. Increase"}, {"content": "", "heading": "increase /ˈɪŋkriːs/ (n): sự tăng lên"}, {"content": "", "heading": "increase /ɪnˈkriːs/ (v): tăng lên"}, {"content": "", "heading": "8. Insult"}, {"content": "", "heading": "insult /ˈɪn.sʌlt/ (n): sự lăng mạ, sỉ nhục"}, {"content": "", "heading": "insult /ɪnˈsʌlt/ (v): lăng mạ, sỉ nhục"}, {"content": "", "heading": "9. Perfect"}, {"content": "", "heading": "perfect /ˈpɜː.fekt/ (adj): hoàn hảo"}, {"content": "", "heading": "perfect /pəˈfekt/ (v): hoàn thiện, làm hoàn hảo"}, {"content": "", "heading": "10. Permit"}, {"content": "", "heading": "permit /ˈpɜː.mɪt/ (n): giấy phép"}, {"content": "", "heading": "permit /pəˈmɪt/ (v): cho phép"}, {"content": "", "heading": "11. Pervert"}, {"content": "", "heading": "pervert /ˈpɜː.vɜːt/ (n): kẻ hư hỏng, kẻ đồi bại"}, {"content": "", "heading": "pervert /pəˈvɜːt/ (v): xuyên tạc, làm hư hỏng, sai lệch"}, {"content": "", "heading": "12. Present"}, {"content": "", "heading": "present /ˈprez.ənt/ (n): món quà"}, {"content": "", "heading": "present /prɪˈzent/ (v): giới thiệu"}, {"content": "", "heading": "13. Produce"}, {"content": "", "heading": "produce /ˈprɒd.juːs/ (n): nông sản, vật phẩm"}, {"content": "", "heading": "produce /prəˈdjuːs/ (v): sản xuất, tạo ra"}, {"content": "", "heading": "14. Protest"}, {"content": "", "heading": "protest /ˈprəʊ.test/ (n): sự phản kháng, kháng nghị"}, {"content": "", "heading": "protest /prəˈtest/ (v): phản kháng"}, {"content": "", "heading": "15. Recall"}, {"content": "", "heading": "recall /ˈriː.kɔːl/ (n): sự làm nhớ lại, hồi tưởng lại"}, {"content": "", "heading": "recall /rɪˈkɔːl/ (v): hồi tưởng, làm nhớ lại"}, {"content": "", "heading": "16. Record"}, {"content": "", "heading": "record /ˈrek.ɔːd/ (n): bản lưu, bản ghi chép"}, {"content": "", "heading": "record /rɪˈkɔːd/ (v): lưu trữ, ghi chép lại"}, {"content": "", "heading": "17. Reject"}, {"content": "", "heading": "reject /ˈriː.dʒekt/ (n): phế phẩm"}, {"content": "", "heading": "reject /rɪˈdʒekt/ (v): từ chối"}, {"content": "", "heading": "18. Suspect"}, {"content": "", "heading": "suspect /ˈsʌs.pekt/ (n): kẻ tình nghi"}, {"content": "", "heading": "suspect /səˈspekt/ (v): nghi ngờ, hoài nghi điều gì đúng, xảy ra"}]}	ACTIVE	GRAMMAR	TRỌNG ÂM - STRESS	\N
68ad59da-7216-46c3-b211-d98381b30cfb	135214f4-611e-45a7-a4b8-076794ab24a0	X - MỘT SỐ CẤU TRÚC THÔNG DỤNG	7	{"title": "X - MỘT SỐ CẤU TRÚC THÔNG DỤNG", "sections": []}	ACTIVE	GRAMMAR	X - MỘT SỐ CẤU TRÚC THÔNG DỤNG	\N
9836d5dd-0dc8-4b3e-a29e-42ebc2616887	a8efe662-9202-4e83-822d-808656858e3e	X - PHÁT ÂM - PRONUNCIATION	7	{"title": "LÝ THUYẾT PHÁT ÂM", "sections": []}	ACTIVE	GRAMMAR	X - PHÁT ÂM - PRONUNCIATION	\N
8eac0baa-cc09-49ee-abe4-ddc17e672476	40a22bef-8b76-400f-bed3-e5c8869ae71d	ĐẢO NGỮ - INVERSIONS	4	{"title": "LÝ THUYẾT ĐẢO NGỮ", "sections": [{"content": "Đảo ngữ là hình thức đảo ngược vị trí thông thường của chủ từ và động từ trong một câu, được dùng để nhấn mạnh một thành phần hay ý nào đó trong câu.", "heading": "A. LÍ THUYẾT"}, {"content": "", "heading": "Các dạng đảo ngữ:"}, {"content": "", "heading": "1. Các cụm từ có NO"}, {"content": "", "heading": "Công thức: No/Not + N + Trợ động từ + S + Động từ"}, {"content": "", "heading": "Ví dụ: Not a tear did she shed when the story ended in a tragedy."}, {"content": "", "heading": "Công thức: At no time = Never = Under/In no circumstances (không bao giờ)"}, {"content": "", "heading": "Ví dụ: At no time did he suspect that his girlfriend was an enemy spy."}, {"content": "", "heading": "Công thức: By no means (hoàn toàn không)"}, {"content": "", "heading": "Ví dụ: By no means is she poor. She only pretends to be."}, {"content": "", "heading": "Công thức: For no reason (không vì lí do gì)"}, {"content": "", "heading": "Ví dụ: For no reason will we surrender."}, {"content": "", "heading": "Công thức: In no way (không sao có thể)"}, {"content": "", "heading": "Ví dụ: In no way could I believe in a ridiculous story."}, {"content": "", "heading": "Công thức: On no condition = On no account + Trợ động từ + S + Động từ (dù bất cứ lí do gì cũng không)"}, {"content": "", "heading": "Ví dụ: On no account should you be late for the exam."}, {"content": "", "heading": "Công thức: No longer (không còn nữa)"}, {"content": "", "heading": "Ví dụ: No longer does he make mistakes."}, {"content": "", "heading": "Công thức: No where + Trợ động từ + S + Động từ (không nơi nào, không ở đâu)"}, {"content": "", "heading": "Ví dụ: No where can the keys be found."}, {"content": "", "heading": "2. Đảo ngữ với các trạng từ phủ định"}, {"content": "", "heading": "Công thức: Never, Rarely, Seldom, Little, Hardly, Scarcely, Barely, ..."}, {"content": "Little did he know the truth.\\nNever in my life have I been in such an embarrassing situation.", "heading": "Ví dụ:"}, {"content": "", "heading": "3. Đảo ngữ với ONLY"}, {"content": "", "heading": "Công thức: Only after + S + V + Trợ động từ + S + V (chỉ sau khi)"}, {"content": "", "heading": "Ví dụ: Only after I had left home did I realize how important my family played a role in my life."}, {"content": "", "heading": "Công thức: Only after + N + Trợ động từ + S + V (chỉ sau khi)"}, {"content": "", "heading": "Ví dụ: Only after his father’s retirement did he take over the company."}, {"content": "", "heading": "Công thức: Only by + V-ing + Trợ động từ + S + V (chỉ bằng cách)"}, {"content": "", "heading": "Ví dụ: Only by studying hard can you pass the exam."}, {"content": "", "heading": "Công thức: Only if + S + V + Trợ động từ + S + V (chỉ nếu)"}, {"content": "", "heading": "Ví dụ: Only if you promise to keep secret will I tell you about it."}, {"content": "", "heading": "Công thức: Only when + S + V + Trợ động từ + S + V (chỉ khi)"}, {"content": "", "heading": "Ví dụ: Only when you grow up can you understand this matter."}, {"content": "", "heading": "Công thức: Only with + N + Trợ động từ + S + V (chỉ với)"}, {"content": "", "heading": "Ví dụ: Only with your help can we manage."}, {"content": "", "heading": "Công thức: Only once/ Only later/ Only in this way/ Only then + Trợ động từ + Chủ ngữ + Động từ"}, {"content": "Only once have I met her.\\nOnly later did I realize I was wrong.", "heading": "Ví dụ:"}, {"content": "", "heading": "4. Hardly / No sooner"}, {"content": "", "heading": "Công thức: Hardly/barely/scarcely + had + S + Vp2 + when + S + V(quá khứ đơn) = No sooner + had + S + Vp2 + than + S + V(quá khứ đơn) (Ngay khi/vừa mới... thì)"}, {"content": "Hardly had I gone to bed when the telephone rang.\\nNo sooner had I gone to bed than the telephone rang.", "heading": "Ví dụ:"}, {"content": "", "heading": "5. Not only ... but also"}, {"content": "", "heading": "Công thức: Not only + Trợ động từ + Chủ ngữ + Động từ + but also + Chủ ngữ + Động từ (không những... mà còn)"}, {"content": "", "heading": "Ví dụ: Not only does she sing beautifully but also she learns well."}, {"content": "", "heading": "6. So/Such ... that"}, {"content": "So + Tính từ + V + chủ ngữ + that + clause\\nSuch + be + N + that + clause/ N + be + such + that + clause (quá... đến nỗi mà)", "heading": "Công thức:"}, {"content": "So beautiful is she that many boys run after her.\\nHer anger was such that she broke the vase.\\n= Such was her anger that she broke the vase.", "heading": "Ví dụ:"}, {"content": "", "heading": "7. Not until/ Not till"}, {"content": "", "heading": "Công thức: Not until/till + Time/Time clause + Trợ động từ + Chủ ngữ + Động từ (mãi đến khi)"}, {"content": "Not until/till midnight did he come home.\\nNot until/till I was 8 did I know how to ride a bike.", "heading": "Ví dụ:"}, {"content": "", "heading": "8. Neither"}, {"content": "", "heading": "Công thức: Neither + Trợ động từ + Chủ ngữ + Động từ"}, {"content": "", "heading": "Ví dụ: Neither is there excitement nor entertainment in this small town."}, {"content": "", "heading": "9. Đảo ngữ với câu điều kiện"}, {"content": "", "heading": "Câu điều kiện loại 1: Should + S + V, V + O / S + will, can... + V"}, {"content": "", "heading": "Ví dụ: Should he come, please tell him to see me."}, {"content": "", "heading": "Câu điều kiện loại 2: Were + S + (to V) + ..., S + would/could + V"}, {"content": "Were I you, I would apply for that job.\\nWere I to have enough money, I would buy that car.", "heading": "Ví dụ:"}, {"content": "", "heading": "Câu điều kiện loại 3: Had + S + Vp2, S + would/could + have + Vp2"}, {"content": "", "heading": "Ví dụ: Had the car in the front not stopped so suddenly, the accidents wouldn't have happened."}, {"content": "", "heading": "10. Although"}, {"content": "= Much as + S + V, S + V\\n= No matter what + S + V, S + V hoặc No matter how + adj/adv + S + V, S + V\\n= However + adj/adv + S + V\\n= Adj/adv + as/though + S + V, S + V", "heading": "Công thức: Although/even though/though + S + V, S + V"}, {"content": "Although the exercise is difficult, the boys can solve it.\\n= Much as the exercise is difficult, the boys can solve it.\\n= No matter how difficult the exercise is, the boys can solve it.\\n= However difficult the exercise is, the boys can solve it.\\n= Difficult as the exercise is, the boys can solve it.", "heading": "Ví dụ:"}, {"content": "", "heading": "11. NOR"}, {"content": "", "heading": "Công thức: Nor + Trợ động từ + Chủ ngữ + Động từ"}, {"content": "", "heading": "Ví dụ: He doesn't smoke, nor does he drink."}, {"content": "", "heading": "12. Đảo ngữ có SO/ NEITHER"}, {"content": "", "heading": "Công thức: So/Neither + Trợ động từ + Chủ ngữ"}, {"content": "I can't sing well, neither can my sister.\\nHe loves football, so do I.", "heading": "Ví dụ:"}, {"content": "", "heading": "13. Đảo ngữ với các trạng từ chỉ phương hướng/ nơi chốn"}, {"content": "", "heading": "Công thức: Adv of place + V + S"}, {"content": "", "heading": "Ví dụ: Near my house is a bus stop."}, {"content": "", "heading": "14. Đảo ngữ với cụm phân từ"}, {"content": "", "heading": "Công thức: Cụm phân từ (V-ing/Vp2) + V + S"}, {"content": "Situated in the central mountains of Alaska is a peak named Denali.\\nComing first in the race was my sister.", "heading": "Ví dụ:"}]}	ACTIVE	GRAMMAR	ĐẢO NGỮ - INVERSIONS	\N
6176ff4f-7a5f-4809-a77e-57a1e6364706	40a22bef-8b76-400f-bed3-e5c8869ae71d	ĐỘNG TỪ KHUYẾT THIẾU - MODAL VERBS	5	{"title": "LÝ THUYẾT ĐỘNG TỪ KHUYẾT THIẾU", "sections": [{"content": "Động từ khuyết thiếu là động từ nhưng lại không chỉ hành động mà nó chỉ giúp bổ nghĩa cho động từ chính.\\nNhững động từ khuyết thiếu này có thể dùng chung cho tất cả các ngôi và không chia theo thì. Các động từ theo sau động từ khuyết thiếu này được giữ nguyên thể.\\nCác động từ khuyết thiếu thường dùng là: can, could, may, might, shall, should, will, would, must, ought to, need, have to.", "heading": "LÝ THUYẾT ĐỘNG TỪ KHUYẾT THIẾU – MODAL VERBS"}, {"content": "", "heading": "1. Can"}, {"content": "", "heading": "Cách dùng: Diễn tả khả năng hiện tại hoặc tương lai mà một người có thể làm được gì, hoặc một sự việc có thể xảy ra."}, {"content": "I can swim - Tôi có thể bơi.\\nIt can rain - Trời có thể mưa.", "heading": "Ví dụ:"}, {"content": "Ví dụ: Can I sit here? - Tôi có thể ngồi đây được không?", "heading": "Chú ý: Can và Could còn được dùng trong câu hỏi đề nghị, xin phép, yêu cầu."}, {"content": "", "heading": "2. Could"}, {"content": "", "heading": "Cách dùng: Diễn tả khả năng xảy ra trong quá khứ."}, {"content": "", "heading": "Ví dụ: My brother could speak English when he was five - Anh trai tôi đã có thể nói tiếng Anh khi anh ấy 5 tuổi."}, {"content": "Ví dụ: Could you please wait a moment? - Bạn có thể đợi một lát được không?", "heading": "Chú ý: Dùng trong câu hỏi đề nghị, xin phép, yêu cầu (trang trọng hơn Can)."}, {"content": "", "heading": "3. Must"}, {"content": "", "heading": "Cách dùng: Diễn đạt sự cần thiết, bắt buộc ở hiện tại hoặc tương lai. Đưa ra lời khuyên hoặc suy luận mang tính chắc chắn, yêu cầu được nhấn mạnh."}, {"content": "You must get up early in the morning - Bạn phải dậy sớm vào buổi sáng.\\nYou must be tired after work hard - Bạn chắc chắn sẽ mệt sau khi làm việc chăm chỉ.\\nYou must be here before 8 a.m - Bạn phải có mặt ở đây trước 8 giờ.", "heading": "Ví dụ:"}, {"content": "Ví dụ: You mustn't smoke here - Bạn không được hút thuốc ở đây.", "heading": "Chú ý: Mustn't - chỉ sự cấm đoán."}, {"content": "", "heading": "4. Have to"}, {"content": "", "heading": "Cách dùng: Diễn tả sự cần thiết phải làm gì nhưng là do khách quan (nội quy, quy định...)."}, {"content": "", "heading": "Ví dụ: I have to wear helmets when driving a motorbike. - Tôi phải đội mũ bảo hiểm khi đi xe máy. (Luật quy định như vậy)"}, {"content": "", "heading": "Chú ý: Don't have to = Don't need to/ needn't (chỉ sự không cần thiết)."}, {"content": "", "heading": "5. May"}, {"content": "", "heading": "Cách dùng: Diễn tả điều gì có thể xảy ra ở hiện tại nhưng không chắc."}, {"content": "", "heading": "Ví dụ: It may be a bomb - Nó có thể là một quả bom."}, {"content": "", "heading": "Chú ý: May và might dùng để xin phép nhưng có tính chất trang trọng hơn can/ could."}, {"content": "", "heading": "6. Might"}, {"content": "", "heading": "Cách dùng: Diễn tả điều gì có thể xảy ra ở quá khứ. Might được dùng không phải là quá khứ của May."}, {"content": "She might not be in his house. - Cô ấy có lẽ không ở nhà anh ta nữa.\\nWhere is John? I don't know. He may/might go out with his friends. - John ở đâu rồi? - Tôi không biết. Có lẽ anh ấy ra ngoài với bạn.", "heading": "Ví dụ:"}, {"content": "Ví dụ: I wonder if he might go there alone.", "heading": "Chú ý: Might ít được dùng trong văn nói, chủ yếu trong câu gián tiếp."}, {"content": "", "heading": "7. Will"}, {"content": "", "heading": "Cách dùng: Diễn đạt, dự đoán sự việc xảy ra trong tương lai. Đưa ra một quyết định tại thời điểm nói."}, {"content": "Tomorrow will be sunny. - Ngày mai trời sẽ nắng.\\nDid you buy sugar? Oh, sorry. I'll go now. - Bạn có mua đường không? - Ồ, xin lỗi. Giờ mình sẽ đi mua.", "heading": "Ví dụ:"}, {"content": "Ví dụ: Will you have a cup of coffee?", "heading": "Chú ý: Dùng Will hay Would trong câu đề nghị, yêu cầu, lời mời."}, {"content": "", "heading": "8. Would"}, {"content": "", "heading": "Cách dùng: Diễn tả một giả định xảy ra hoặc dự đoán sự việc có thể xảy ra trong quá khứ."}, {"content": "", "heading": "Ví dụ: He was so tired. He would get up late tomorrow - Anh ấy rất mệt. Ngày mai, chắc anh ấy sẽ dậy muộn."}, {"content": "Ví dụ: Would you like a cake?", "heading": "Chú ý: Dùng trong lời mời lịch sự."}, {"content": "", "heading": "9. Shall"}, {"content": "", "heading": "Cách dùng: Dùng để xin ý kiến, lời khuyên. \\"Will\\" được sử dụng nhiều hơn."}, {"content": "", "heading": "Ví dụ: Where shall we eat tonight? - Tối nay chúng ta ăn ở đâu?"}, {"content": "", "heading": "Chú ý: Chỉ dùng với hai ngôi \\"I\\" và \\"We\\"."}, {"content": "", "heading": "10. Should"}, {"content": "", "heading": "Cách dùng: Chỉ sự bắt buộc hay bổn phận nhưng ở mức độ nhẹ hơn \\"Must\\". Đưa ra lời khuyên, ý kiến. Dùng để suy đoán."}, {"content": "You should send this report by 8th September. - Bạn nên gửi báo cáo này trước ngày 8 tháng Chín.\\nYou should call her.\\nShe worked hard, she should get the best result. - Cô ấy học rất chăm, cô ấy sẽ đạt được kết quả cao nhất.", "heading": "Ví dụ:"}, {"content": "", "heading": "11. Ought to"}, {"content": "", "heading": "Cách dùng: Chỉ sự bắt buộc. Mạnh hơn \\"Should\\" nhưng chưa bằng \\"Must\\"."}, {"content": "", "heading": "Ví dụ: You ought not to eat candy at night. - Bạn không nên ăn kẹo vào buổi tối."}, {"content": "", "heading": "II. Lưu ý"}, {"content": "Ta sử dụng \\"be able to\\" và \\"can\\" để diễn tả một khả năng hay sự có thể. Tuy nhiên, \\"can\\" không có dạng tương lai nên ta sử dụng \\"will be able to\\".\\nVí dụ:\\nThey can come on Friday. ~ Họ có thể đến vào thứ Sáu.\\nJack will be able to come next week. ~ Jack có thể đến vào tuần tới. \\"Could\\" trong quá khứ diễn tả một khả năng chung để làm một việc gì đó.\\nVí dụ: He could swim when he was five. ~ Anh ấy có thể bơi từ hồi lên 5 tuổi. Tuy nhiên, nếu một người nào đó trong một hoàn cảnh phải làm một việc gì đó, cố gắng xoay xở để làm một việc gì đó thì ta sử dụng \\"was/ were able to\\".\\nVí dụ: In spite of his broken leg, he was able to get out of the burning house. (Mặc dù gãy chân, anh ấy vẫn có thể thoát ra khỏi ngôi nhà đang cháy.)", "heading": "1. Sự khác nhau giữa \\"can\\" và \\"be able to\\""}, {"content": "Need vừa là động từ thường, vừa là động từ khuyết thiếu.", "heading": "2. Need là động từ thường hay động từ khuyết thiếu?"}, {"content": "Nó phải dùng trợ động từ khi thành lập câu phủ định và nghi vấn. Động từ theo sau nó phải dùng dạng \\"to infinitive\\".\\nVí dụ:\\nShe needs to see you. ~ Cô ấy cần gặp bạn.\\nShe doesn't need to see you. ~ Cô ấy không cần gặp bạn.\\nDoes she need to see you? ~ Cô ấy có cần gặp bạn không?", "heading": "a. Need là động từ thường"}, {"content": "Ví dụ: Your shoes need cleaning/ to be cleaned. ~ Giày của bạn cần được giặt.", "heading": "Cấu trúc bị động Something + need + Ving = Something + need + to be + Vp2 (Cái gì cần được làm)"}, {"content": "Khi là động từ khuyết thiếu NEED chỉ có hình thức hiện tại và có đầy đủ đặc tính của một động từ khuyết thiếu.\\nVí dụ:\\nNeed he work so hard? (Anh ấy có cần phải làm việc chăm chỉ vậy không?)\\nYou needn't go yet, need you? (Bạn không cần phải đi đúng không?) Có một điều cần nhớ là động từ khuyết thiếu NEED không dùng ở thể xác định. Nó chỉ được dùng ở thể phủ định và nghi vấn. Khi dùng ở thể xác định, nó phải được dùng với một từ ngữ phủ định.\\nYou needn't see him, but I must. (Bạn không cần gặp anh ấy, nhưng tôi phải gặp.) I hardly need say how much I enjoyed the holiday. (Tôi không cần nói về việc tôi đã tận hưởng kì nghỉ như thế nào.)", "heading": "b. Need là động từ khuyết thiếu"}, {"content": "Để đưa ra lời khuyên, ta dùng cấu trúc:\\nI think you should + V (bare): Tôi nghĩ bạn nên làm gì\\nVí dụ: I think you should take a rest for a few days. (Tôi nghĩ bạn nên nghỉ ngơi vài ngày.)\\nI don't think you should + V (bare): Tôi không nghĩ bạn nên làm gì\\nVí dụ: I don't think you should spend much time playing games. (Tôi không nghĩ bạn nên dành nhiều thời gian vào chơi games.)\\nLưu ý: Không được dùng I think you shouldn't + V (bare)", "heading": "c. Should - Với ý nghĩa đưa ra lời khuyên"}, {"content": "\\"Dare\\" có nghĩa là \\"dám, cả gan\\" có thể được xem như một động từ khuyết lẫn động từ thường. Khi là một động từ khuyết thiếu, nó có đầy đủ đặc tính của loại động từ này.\\nVí dụ:\\nDare he go and speak to her? (động từ khuyết thiếu) (Anh ta dám đến và nói với cô ấy sao?)\\nYou daren't climb that tree, dare you? (động từ khuyết thiếu) (Bạn không dám trèo lên cái cây đó, đúng không?)\\nHe doesn't dare to answer my letter. (động từ thường) (Anh ta không dám trả lời thư của tôi.)\\nShe didn't dare to say a word, did she? (động từ thường) (Cô ấy đã không dám nói một từ nào đúng không?)\\nThành ngữ \\"I dare say\\" có nghĩa là \\"có thể, có lẽ\\" đồng nghĩa với các từ \\"perhaps\\", \\"it is probable\\". Thành ngữ này thường không dùng với chủ từ nào khác ngoài ngôi thứ nhất.\\nVí dụ: He is not here yet, but I dare say he will come later. (Anh ấy không có ở đây, có thể anh ấy sẽ đến sau.)", "heading": "d. Dare"}, {"content": "", "heading": "III. Modal perfect - modal verbs + have + Vp2"}, {"content": "Ví dụ:\\nThe grass is wet. It must have rained last night. (Cỏ ướt. Chắc là tối qua có mưa.)\\nI'm sorry, she's not here. She must have left already. (Tôi rất lấy làm tiếc, cô ấy không còn ở đây nữa. Chắc là cô ấy đã đi rồi.)\\nLưu ý: Ngoài dạng dùng \\"Must\\" trong những suy luận quá khứ, người ta còn dùng \\"Must be\\" trong suy đoán hiện tại. Ví dụ: She has been working all day long. She must be very tired now. (Cô ấy đã làm việc suốt cả ngày ròng. Chắc giờ cô ấy phải mệt lắm.)", "heading": "1. Must + have + Vp2: chỉ sự suy đoán logic dựa trên những hiện tượng có thật ở quá khứ."}, {"content": "Ví dụ:\\nHe should have told the truth about what he saw. (Anh ấy lẽ ra đã phải nói thật những gì mà anh ấy đã trông thấy.)\\nI'm sorry that I'm late for work. I should have woken up earlier. (Tôi xin lỗi vì đến muộn làm. Tôi lẽ ra đã phải thức dậy sớm hơn.)", "heading": "2. Should + have + Vp2: chỉ một việc lẽ ra đã phải xảy ra trong quá khứ nhưng vì lí do nào đó lại không xảy ra."}, {"content": "Ví dụ:\\nIt can't have been Mary's sister who you saw on the bus yesterday because she doesn't have a sister. (Người bạn nhìn thấy trên xe buýt ngày hôm qua không thể là chị gái của Mary được, vì cô ấy làm gì có chị gái.)", "heading": "3. Can't + have + Vp2: chỉ những việc không thể đã xảy ra vì có căn cứ, cơ sở rõ ràng."}, {"content": "Ví dụ:\\nIt didn't rain any more last night. We needn't have put up the tent. (Tối qua trời không mưa. Chúng ta lẽ ra không cần thiết phải dựng lều.)", "heading": "4. Needn't + have + Vp2: chỉ những việc lẽ ra đã không cần thiết phải làm nhưng đã làm."}, {"content": "Ví dụ:\\nShe didn't go to school yesterday. She might have been ill. I'm not sure. (Cô ấy không đến trường ngày hôm qua. Cô ấy có thể đã bị ốm. Tôi không chắc.)", "heading": "5. May/might + have + Vp2: chỉ những việc có thể đã xảy ra nhưng không chắc chắn."}, {"content": "Ví dụ: He could have gotten the ticket for the concert last night. (Lẽ ra anh ấy đã có thể có được tấm vé đi xem hoà nhạc tối qua.) => Trên thực tế là anh ấy không có được tấm vé đi xem hoà nhạc tối qua", "heading": "6. Could + have + Vp2: chỉ những việc có lẽ đã xảy ra nhưng trên thực tế là không."}]}	ACTIVE	GRAMMAR	ĐỘNG TỪ KHUYẾT THIẾU - MODAL VERBS	\N
ccb69ba1-1992-4465-b510-21bb546e098d	6fa3953c-7b65-4097-8f80-f66ee2f20108	Từ vựng: CULTURE IDENTITY	1	{"topic": "CULTURE IDENTITY", "words": [{"type": "a", "word": "Aboriginal", "meaning": "nguyên sơ, nguyên thủy", "phonetic": "/ˌæbəˈrɪdʒənəl/"}, {"type": "n", "word": "Ancestor", "meaning": "tổ tiên", "phonetic": "/ˈænsestər/"}, {"type": "n", "word": "Anniversary", "meaning": "lễ kỉ niệm, ngày lễ", "phonetic": "/ˌænɪˈvɜːsəri/"}, {"type": "n", "word": "Ceremony", "meaning": "nghi thức, nghi lễ", "phonetic": "/ˈserəməni/"}, {"type": "n", "word": "Celebration", "meaning": "sự tổ chức", "phonetic": "/ˌseləˈbreɪʃən/"}, {"type": "n", "word": "Bicentenary", "meaning": "lễ kỉ niệm cứ 200 năm tổ chức 1 lần", "phonetic": "/ˌbaɪsenˈtiːnəri/"}, {"type": "n", "word": "Assimilation", "meaning": "sự đồng hóa", "phonetic": "/əˌsɪmɪˈleɪʃən/"}, {"type": "n", "word": "Bravery", "meaning": "sự dũng cảm", "phonetic": "/ˈbreɪvəri/"}, {"type": "n", "word": "Bridegroom", "meaning": "chú rể", "phonetic": "/ˈbraɪdɡruːm/"}, {"type": "n", "word": "Conflict", "meaning": "sự xung đột", "phonetic": "/ˈkɒnflɪkt/"}, {"type": "n", "word": "Contract", "meaning": "hợp đồng", "phonetic": "/ˈkɒntrækt/"}, {"type": "a", "word": "Contractual", "meaning": "thuộc hợp đồng", "phonetic": "/kənˈtræktʃuəl/"}, {"type": "adv", "word": "Conversely", "meaning": "ngược lại", "phonetic": "/ˈkɒnvɜːsli/"}, {"type": "n", "word": "Coordinator", "meaning": "người phối hợp", "phonetic": "/kəʊˈɔːdɪneɪtər/"}, {"type": "n", "word": "Currency", "meaning": "tiền tệ", "phonetic": "/ˈkʌrənsi/"}, {"type": "n", "word": "Custom", "meaning": "phong tục", "phonetic": "/ˈkʌstəm/"}, {"type": "adv", "word": "Deliberately", "meaning": "một cách có chủ ý, có toan tính", "phonetic": "/dɪˈlɪbərətli/"}, {"type": "v", "word": "Denounce", "meaning": "tố cáo, vạch mặt", "phonetic": "/dɪˈnaʊns/"}, {"type": "n", "word": "Depravity", "meaning": "sự trụy lạc", "phonetic": "/dɪˈprævəti/"}, {"type": "v", "word": "Dismiss", "meaning": "sa thải", "phonetic": "/dɪˈsmɪs/"}, {"type": "n", "word": "Dismissal", "meaning": "sự sa thải", "phonetic": "/dɪˈsmɪsəl/"}, {"type": "a", "word": "Dismissive", "meaning": "gạt bỏ, xem thường", "phonetic": "/dɪˈsmɪsɪv/"}, {"type": "n", "word": "Diversity", "meaning": "sự đa dạng", "phonetic": "/daɪˈvɜːsəti/"}, {"type": "a", "word": "Diverse", "meaning": "đa dạng", "phonetic": "/daɪˈvɜːs/"}, {"type": "v", "word": "Diversify", "meaning": "đa dạng hóa", "phonetic": "/daɪˈvɜːsɪfaɪ/"}, {"type": "n", "word": "Diversification", "meaning": "sự đa dạng hóa", "phonetic": "/daɪˌvɜːsɪfɪˈkeɪʃn/"}, {"type": "adv", "word": "Extremely", "meaning": "cực kì", "phonetic": "/ɪkˈstriːmli/"}, {"type": "adv", "word": "Completely", "meaning": "hoàn toàn", "phonetic": "/kəmˈpliːtli/"}, {"type": "adv", "word": "Tremendously", "meaning": "khủng khiếp, ghê gớm", "phonetic": "/trɪˈmendəsli/"}, {"type": "adv", "word": "Dramatically", "meaning": "đột ngột", "phonetic": "/drəˈmætɪkəli/"}, {"type": "n", "word": "Fate", "meaning": "vận mệnh, định mệnh", "phonetic": "/feɪt/"}, {"type": "n", "word": "Federation", "meaning": "liên đoàn", "phonetic": "/ˌfedəˈreɪʃən/"}, {"type": "n", "word": "Folktale", "meaning": "truyện dân gian", "phonetic": "/ˈfəʊkˌteɪl/"}, {"type": "n", "word": "Heritage", "meaning": "di sản", "phonetic": "/ˈherɪtɪdʒ/"}, {"type": "a", "word": "Hilarious", "meaning": "vui nhộn", "phonetic": "/hɪˈleəriəs/"}, {"type": "n", "word": "Homophone", "meaning": "từ đồng âm", "phonetic": "/ˈhɒməfəʊn/"}, {"type": "v", "word": "Identify", "meaning": "nhận diện, nhận dạng", "phonetic": "/aɪˈdentɪfaɪ/"}, {"type": "n", "word": "Identification", "meaning": "sự đồng nhất hoá", "phonetic": "/aɪˌdentɪfɪˈkeɪʃən/"}, {"type": "a", "word": "Identical", "meaning": "giống nhau", "phonetic": "/aɪˈdentɪkəl/"}, {"type": "n", "word": "Identity", "meaning": "tính đồng nhất; đặc tính", "phonetic": "/aɪˈdentəti/"}, {"type": "n", "word": "Incense", "meaning": "nhang, hương", "phonetic": "/ˈɪnsens/"}, {"type": "a", "word": "Indigenous